import type { Faq } from './types';

export const philosopherFaqs: Record<string, Faq[]> = {
  'thales-of-miletus': [
    { question: 'Who was Thales of Miletus?', answer: 'Thales of Miletus (c. 624–546 BCE) is often considered the first philosopher in the Western tradition. He sought natural rather than mythological explanations for phenomena and is known for predicting a solar eclipse and measuring the height of pyramids using shadows.' },
    { question: 'What did Thales believe?', answer: 'Thales of Miletus believed that water is the fundamental substance underlying all of reality. He proposed that a single natural principle, called the arche, is the source from which all things originate and to which all things return.' },
    { question: 'Why is Thales important?', answer: 'Thales of Miletus founded Western philosophy and natural science by insisting on rational, naturalistic explanations rather than mythological narratives. His question about the fundamental substance of reality launched the entire tradition of philosophical and scientific inquiry in the West.' },
    { question: "What are Thales of Miletus's major works?", answer: 'Thales of Miletus left no surviving written works. His ideas are known entirely through later sources, most notably the writings of Aristotle, who identified Thales as the first natural philosopher.' },
    { question: 'What is the arche in philosophy?', answer: 'The arche is the fundamental principle or substance from which all things originate. Thales of Miletus was the first philosopher to propose an arche, arguing that water is the underlying basis of all reality, a claim that launched centuries of philosophical debate about the nature of the cosmos.' },
  ],
  'heraclitus': [
    { question: 'Who was Heraclitus?', answer: 'Heraclitus (c. 535–475 BCE) was a Pre-Socratic Greek philosopher known as "The Obscure" for his cryptic aphorisms. He believed the cosmos is in perpetual flux, governed by the Logos, a rational principle underlying all change, and saw reality as a unity of opposites.' },
    { question: 'What did Heraclitus believe?', answer: 'Heraclitus believed that everything flows and change is the fundamental nature of reality. He argued that apparent opposites such as day and night, life and death, and war and peace are aspects of a single underlying process governed by the Logos, or universal rational principle.' },
    { question: 'Why is Heraclitus important?', answer: 'Heraclitus influenced some of the most significant thinkers in Western philosophy, including Plato, the Stoics, Hegel, and Nietzsche. His doctrine of flux and the unity of opposites shaped dialectical thinking and process philosophy, and his concept of the Logos became central to Stoic metaphysics.' },
    { question: "What are Heraclitus's major works?", answer: 'Heraclitus wrote a single work, On Nature, which survives only in fragments. These fragments, preserved by later writers, contain his famous teachings on flux, the unity of opposites, and the Logos as the rational order governing the cosmos.' },
    { question: 'What did Heraclitus mean by the river fragment?', answer: 'Heraclitus argued that you cannot step into the same river twice because both the water and the person have changed. His point was not simply that things change, but that identity itself is dynamic, and what we call a stable thing is really a pattern maintained through continuous transformation.' },
  ],
  'parmenides': [
    { question: 'Who was Parmenides?', answer: 'Parmenides (c. 515–450 BCE) was a Pre-Socratic philosopher and founder of the Eleatic school. He composed a philosophical poem arguing that reality is a single, unchanging, eternal unity, and his rigorous logical arguments against change forced all subsequent thinkers to explain how change is possible.' },
    { question: 'What did Parmenides believe?', answer: 'Parmenides believed that what exists is eternal and unchanging, and that change and multiplicity are illusions. He argued that change would require something to come from non-being, which by definition does not exist, making change logically impossible.' },
    { question: 'Why is Parmenides important?', answer: "Parmenides' arguments shaped the course of Western metaphysics by forcing every subsequent thinker to account for the possibility of change. Plato's Theory of Forms, Aristotle's distinction between potentiality and actuality, and the Atomists' postulation of void were all direct responses to his challenge." },
    { question: "What are Parmenides's major works?", answer: 'Parmenides wrote a single philosophical poem, On Nature, which survives only in fragments. The poem presents two paths of inquiry: the Way of Truth, which argues that Being is eternal and unchanging, and the Way of Seeming, which describes the world of mortal opinion.' },
    { question: "What is Parmenides' Way of Truth?", answer: "Parmenides' Way of Truth argues that Being is eternal, unchanging, indivisible, and complete. Through rigorous deductive reasoning, he demonstrated that change requires something to come from non-being, which is logically impossible, leading to the conclusion that all apparent change belongs to the realm of mortal opinion rather than reality." },
  ],
  'socrates': [
    { question: 'Who was Socrates?', answer: 'Socrates (c. 470–399 BCE) was an Athenian philosopher who shifted the focus of philosophy from cosmology to ethics and human life. He wrote nothing himself; his thought survives through the dialogues of his student Plato and the memoirs of Xenophon. He was tried and executed in 399 BCE on charges of impiety and corrupting the youth of Athens.' },
    { question: 'What did Socrates believe?', answer: 'Socrates believed that true wisdom lies in recognizing one\'s own ignorance and that virtue is a form of knowledge. He argued that no one does wrong willingly and that all wrongdoing stems from ignorance of the good, a position known as Socratic intellectualism.' },
    { question: 'Why is Socrates important?', answer: 'Socrates established the method of philosophical inquiry through dialogue, which remains the basis of critical thinking, education, and law. His approach of systematic questioning to reveal contradictions in beliefs created the foundation of Western pedagogy and the legal method of cross-examination.' },
    { question: "What are Socrates's major works?", answer: 'Socrates left no written works of his own. His philosophy is preserved almost entirely through the dialogues of Plato, such as the Apology, Crito, and Phaedo, as well as through the memoirs of Xenophon and references in Aristotle.' },
    { question: 'What is the Socratic Method?', answer: 'The Socratic Method is a form of cooperative dialogue in which systematic questioning is used to reveal contradictions in a person\'s beliefs and arrive at deeper understanding. Socrates would ask someone to define a concept, then test that definition with counterexamples until inconsistencies emerged, prompting further refinement of the idea.' },
  ],
  'plato': [
    { question: 'Who was Plato?', answer: 'Plato (c. 428–348 BCE) was an Athenian philosopher born into a prominent aristocratic family who became a student of Socrates. After Socrates\' execution, he traveled widely and around 387 BCE founded the Academy in Athens, often considered the Western world\'s first university, which operated for over nine centuries.' },
    { question: 'What did Plato believe?', answer: 'Plato believed that reality consists of eternal, perfect Forms and that the physical world is merely their imperfect shadow. He argued that the most real things are not those we can touch but those we can only grasp through reason, with the Form of the Good standing at the summit of all reality and knowledge.' },
    { question: 'Why is Plato important?', answer: "Plato's work shaped every branch of philosophy that followed, leading Alfred North Whitehead to remark that all Western philosophy consists of footnotes to Plato. His roughly thirty dialogues explore virtually every philosophical question, from reality and knowledge to justice, beauty, and the ideal state, and his Academy trained generations of thinkers including Aristotle." },
    { question: "What are Plato's major works?", answer: 'Plato wrote approximately thirty dialogues, including the Republic, which explores justice and the ideal state; the Symposium on love; the Phaedo on the immortality of the soul; and the Timaeus on cosmology. Other significant works include the Theaetetus on knowledge, the Meno on virtue, and the Laws on political philosophy.' },
    { question: "What is Plato's Theory of Forms?", answer: "Plato's Theory of Forms holds that behind every particular thing in the physical world there exists an eternal, perfect, unchanging Form. Physical objects participate in these Forms but are always imperfect, changing copies of them. At the summit of this hierarchy stands the Form of the Good, which Plato compared to the sun as the source that illuminates all other Forms and makes knowledge possible." },
  ],
  'aristotle': [
    { question: 'Who was Aristotle?', answer: 'Aristotle (384–322 BCE) was a Greek philosopher born in Stagira who studied at Plato\'s Academy for twenty years before founding his own school, the Lyceum, in Athens. He tutored Alexander the Great and produced an extraordinary body of work covering logic, physics, biology, metaphysics, ethics, politics, rhetoric, and poetics.' },
    { question: 'What did Aristotle believe?', answer: 'Aristotle believed that knowledge comes from empirical observation and that virtue is the golden mean between extremes. Where Plato looked toward abstract Forms, Aristotle insisted that knowledge begins with careful observation of particular things and that understanding requires identifying the purpose or function of what is being studied.' },
    { question: 'Why is Aristotle important?', answer: "Aristotle's logic dominated Western thought for over two thousand years, and his ethics, politics, and metaphysics remain central to philosophy today. He essentially invented formal logic, pioneered systematic biological research, and his surviving works cover an astonishing range of disciplines that shaped scholarship across the medieval Islamic and Christian worlds." },
    { question: "What are Aristotle's major works?", answer: "Aristotle's major surviving works include the Nicomachean Ethics on virtue and happiness, the Politics on governance, the Metaphysics on the nature of being, and the Poetics on literary theory. His logical writings, collected as the Organon, founded formal logic, while his Physics and De Anima address the natural world and the soul." },
    { question: "What is Aristotle's Golden Mean?", answer: "Aristotle's Golden Mean is the principle that every moral virtue occupies a balanced midpoint between two vices, one of excess and one of deficiency. For example, courage is the mean between cowardice and recklessness. The mean is not a mathematical midpoint but a practical judgment that varies with the person and situation, requiring the exercise of practical wisdom." },
  ],
  'zeno-of-citium': [
    { question: 'Who was Zeno of Citium?', answer: 'Zeno of Citium (c. 334–262 BCE) was a philosopher from Cyprus who founded the Stoic school of philosophy in Athens. He taught from the Stoa Poikile (Painted Porch), from which Stoicism takes its name, and his school became one of the dominant philosophical movements of antiquity.' },
    { question: 'What did Zeno of Citium believe?', answer: 'Zeno of Citium believed that virtue, achieved through reason and self-discipline, is the only true good. He taught that the good life consists in living in harmony with nature and that external goods like wealth and reputation are merely preferred indifferents, not necessary for happiness.' },
    { question: 'Why is Zeno of Citium important?', answer: 'Zeno of Citium founded Stoicism, which profoundly influenced Roman culture through figures like Seneca, Epictetus, and Marcus Aurelius. Stoic ideas shaped early Christianity, informed Enlightenment conceptions of natural law and universal rights, and directly inspired modern cognitive behavioral therapy.' },
    { question: "What are Zeno of Citium's major works?", answer: 'Zeno of Citium\'s original writings have not survived. His ideas are known primarily through fragments preserved by Diogenes Laertius and through the works of later Stoics such as Seneca, Epictetus, and Marcus Aurelius, who developed and transmitted his philosophical system.' },
    { question: 'What are preferred indifferents in Stoic philosophy?', answer: 'Preferred indifferents are things like health, wealth, and reputation that are naturally preferable but not necessary for happiness according to Stoic philosophy. Zeno of Citium taught that only virtue is truly good and only vice truly bad, while everything else falls into this middle category where rational selection operates but nothing can add to or subtract from genuine well-being.' },
  ],
  'epicurus': [
    { question: 'Who was Epicurus?', answer: 'Epicurus (341–270 BCE) was a Greek philosopher born on the island of Samos who founded his school, known as The Garden, in Athens around 306 BCE. His school was remarkably inclusive for its time, welcoming women and enslaved people as full participants in philosophical discussion.' },
    { question: 'What did Epicurus believe?', answer: 'Epicurus believed that pleasure, understood as the absence of pain and anxiety, is the highest good. He distinguished between active enjoyment and a stable state of tranquility, teaching that true happiness comes not from pursuing ever-greater stimulation but from achieving peace of mind through simple pleasures, friendship, and philosophical understanding.' },
    { question: 'Why is Epicurus important?', answer: 'Epicurus influenced the Roman poet Lucretius, whose poem De Rerum Natura helped catalyze the Scientific Revolution when it was rediscovered in 1417. His materialist philosophy anticipated modern scientific methodology, and his ethical framework influenced Enlightenment thought, utilitarianism, and modern secular approaches to well-being.' },
    { question: "What are Epicurus's major works?", answer: 'Epicurus reportedly wrote over 300 scrolls, but almost all have been lost. His surviving works include the Letter to Menoeceus on ethics, the Letter to Herodotus on physics, and collections of maxims known as the Principal Doctrines and Vatican Sayings.' },
    { question: 'What did Epicurus teach about the fear of death?', answer: 'Epicurus argued that death is nothing to us because it is the complete cessation of all sensation. Since we never actually experience death, fearing it means fearing something we will never encounter. He drew a parallel with the time before our birth, reasoning that if we do not grieve over the eternity before we existed, we should not dread the eternity after we cease to exist.' },
  ],
  'diogenes-of-sinope': [
    { question: 'Who was Diogenes of Sinope?', answer: 'Diogenes of Sinope (c. 412–323 BCE) was the most famous Cynic philosopher, known for living in a ceramic jar, carrying a lantern in search of an honest man, and telling Alexander the Great to stop blocking his sunlight. His philosophy was one of radical simplicity and deliberate provocation against social conventions.' },
    { question: 'What did Diogenes of Sinope believe?', answer: 'Diogenes of Sinope believed that civilization, wealth, and social norms corrupt human nature. He taught that people should reject all conventions and possessions and live according to nature in radical simplicity, arguing that true freedom comes from needing almost nothing.' },
    { question: 'Why is Diogenes of Sinope important?', answer: 'Diogenes of Sinope inspired the development of Stoicism, as Zeno of Citium reportedly took up philosophy after encountering Cynic teachings. He coined the concept of cosmopolitanism, declaring himself a citizen of the world, an idea that influenced Enlightenment universalism and the modern human rights tradition.' },
    { question: "What are Diogenes of Sinope's major works?", answer: 'Diogenes of Sinope left no surviving written works. His philosophy is known entirely through anecdotes recorded by later writers, most notably Diogenes Laertius. These vivid stories of his provocative behavior and witty exchanges served as philosophical arguments conducted through action rather than text.' },
    { question: 'What is Cynicism in philosophy?', answer: 'Cynicism is a philosophical school founded on the distinction between nature and convention, arguing that most of what people value, including wealth, status, and social norms, is artificial rather than natural. Diogenes of Sinope, its most famous practitioner, demonstrated that a human being needs almost nothing to live well and that conventional desires are chains disguised as luxuries.' },
  ],
  'epictetus': [
    { question: 'Who was Epictetus?', answer: 'Epictetus (c. 50–135 CE) was a Stoic philosopher who was born into slavery and later gained his freedom to become one of the most influential teachers of Stoicism. His teachings, recorded by his student Arrian in the Discourses and the Enchiridion, emphasize the dichotomy of control and practical wisdom.' },
    { question: 'What did Epictetus believe?', answer: "Epictetus believed that it is not things that disturb us but our judgments about things. He taught that we should focus only on what is within our control, namely our opinions, desires, and intentions, and accept everything else with equanimity, since freedom comes from mastering our inner responses rather than external circumstances." },
    { question: 'Why is Epictetus important?', answer: 'Epictetus directly influenced Marcus Aurelius, whose Meditations drew heavily on his teachings, and his Enchiridion remains one of the most widely used guides to practical philosophy. His core insight that emotional disturbance originates in our interpretations rather than in external events was explicitly acknowledged by the founders of cognitive behavioral therapy as a direct predecessor of their methods.' },
    { question: "What are Epictetus's major works?", answer: "Epictetus wrote nothing himself. His teachings survive through his student Arrian, who recorded them in the Discourses, a collection of philosophical lectures, and the Enchiridion (Handbook), a concise manual of Stoic practical ethics that distills his key principles into brief, actionable guidance." },
    { question: "What is Epictetus's dichotomy of control?", answer: "Epictetus's dichotomy of control is the principle that some things are within our power, such as our opinions, desires, and intentions, while other things are not, such as our body, possessions, and reputation. He taught that all human suffering comes from confusing these two categories, and that freedom is achieved by focusing energy only on what we can actually influence." },
  ],
  'seneca': [
    { question: 'Who was Seneca?', answer: 'Seneca (c. 4 BCE–65 CE), fully named Lucius Annaeus Seneca, was a Roman Stoic philosopher, statesman, dramatist, and tutor to Emperor Nero. His letters and essays provide practical wisdom on managing emotions, facing adversity, and living ethically, making Stoicism accessible and applicable to daily life.' },
    { question: 'What did Seneca believe?', answer: 'Seneca believed that we suffer more in imagination than in reality. He taught that most human misery comes from anticipating misfortunes that may never occur, wasting time on trivial pursuits, and failing to examine how we spend our limited lives.' },
    { question: 'Why is Seneca important?', answer: "Seneca's practical philosophy has experienced a major modern revival, and his works are among the most widely read Stoic texts today. His Letters to Lucilius pioneered the personal essay as a philosophical form, directly influencing Montaigne, and his techniques for managing adversity and anxiety anticipated key principles in modern cognitive psychology." },
    { question: "What are Seneca's major works?", answer: "Seneca's major works include the Letters to Lucilius, 124 surviving letters of philosophical advice; On the Shortness of Life, an essay on the proper use of time; On Anger, a treatise on emotional management; and On the Happy Life, which addresses the relationship between virtue and pleasure. He also wrote On Providence and several tragedies." },
    { question: 'What is premeditatio malorum?', answer: "Premeditatio malorum, or the premeditation of adversity, is a Stoic technique developed by Seneca in which one visualizes potential misfortunes in advance to reduce their emotional impact. By calmly imagining worst-case scenarios before they occur, the mind becomes prepared rather than overwhelmed, and paradoxically, the practice produces greater gratitude for what one currently has." },
  ],
  'marcus-aurelius': [
    { question: 'Who was Marcus Aurelius?', answer: 'Marcus Aurelius (121–180 CE) was the last of Rome\'s Five Good Emperors and a practicing Stoic philosopher. He wrote his Meditations as private philosophical reflections during military campaigns along the Danube frontier, never intending them for publication, yet they became one of the most enduring works of practical philosophy.' },
    { question: 'What did Marcus Aurelius believe?', answer: 'Marcus Aurelius believed that we should focus on what is within our control and accept the rest with equanimity. He taught that external events cannot harm us unless we allow our judgments about them to disturb us, and that our primary duty is service to the common good.' },
    { question: 'Why is Marcus Aurelius important?', answer: "Marcus Aurelius's Meditations has remained continuously read for nearly two thousand years, offering a rare window into a world leader's private philosophical practice. That a Roman emperor with absolute power chose to govern himself by Stoic principles of duty, humility, and rational self-examination has inspired leaders, soldiers, and public servants across centuries." },
    { question: "What are Marcus Aurelius's major works?", answer: "Marcus Aurelius's sole surviving work is the Meditations, a collection of private philosophical reflections written in Greek during military campaigns. Organized into twelve books, the Meditations consist of personal notes and self-exhortations on Stoic principles, covering themes of duty, impermanence, self-discipline, and the inner life." },
    { question: 'What is the inner citadel in Stoic philosophy?', answer: "The inner citadel is a concept central to Marcus Aurelius's Meditations, referring to the mind's capacity to remain undisturbed by external events. It holds that within each person there is an inviolable fortress of rational judgment that no external force, whether invasion, illness, or loss, can breach unless one voluntarily surrenders it through false judgments about what has occurred." },
  ],
  'plotinus': [
    { question: 'Who was Plotinus?', answer: 'Plotinus (c. 204–270 CE) was the founder of Neoplatonism, a philosophical system that synthesized Platonic, Aristotelian, and Stoic ideas. He argued that all reality flows from a single transcendent source called the One, and his philosophy became one of the most influential bridges between ancient and medieval thought.' },
    { question: 'What did Plotinus believe?', answer: 'Plotinus believed that all reality emanates from the One, an ineffable, transcendent unity beyond being. From the One flows Mind (Nous), which contains the Platonic Forms; from Mind flows Soul, which organizes the material world; and from Soul flows Matter, the lowest and least real level of existence.' },
    { question: 'Why is Plotinus important?', answer: "Plotinus served as a crucial bridge between ancient and medieval thought. His Neoplatonic framework shaped Christian theology through Augustine, influenced Islamic and Jewish philosophy, and provided the philosophical structure for nearly all Western mystical traditions, from Meister Eckhart to the Renaissance Platonists." },
    { question: "What are Plotinus's major works?", answer: "Plotinus's writings were compiled by his student Porphyry into a single work called the Enneads, organized into six groups of nine treatises each. The Enneads cover topics ranging from the nature of the One and the structure of reality to the soul's descent into matter and its ascent back toward union with the divine." },
    { question: 'What is emanation in Neoplatonic philosophy?', answer: 'Emanation is the process by which all reality flows outward from the One, like light radiating from a source. Unlike creation, emanation is not a deliberate act of will but a necessary and eternal overflow of the One\'s perfection. Each level of reality, from Mind to Soul to Matter, is a progressively dimmer reflection of what is above it.' },
  ],
  'pythagoras': [
    { question: 'Who was Pythagoras?', answer: 'Pythagoras (c. 570–495 BCE) was a Greek mathematician, mystic, and philosopher who founded a quasi-religious community in southern Italy. He taught that the cosmos is governed by mathematical harmony and that number is not simply a tool for describing reality but constitutes reality itself.' },
    { question: 'What did Pythagoras believe?', answer: 'Pythagoras believed that numbers and mathematical relationships are the fundamental nature of reality. His discovery that musical harmonies correspond to precise mathematical ratios led him to conclude that the entire cosmos is structured by mathematical order, from the motions of heavenly bodies to the cycles of the seasons.' },
    { question: 'Why is Pythagoras important?', answer: "Pythagoras founded mathematical philosophy and his conviction that nature is fundamentally mathematical was vindicated by Kepler's laws of planetary motion, Newton's mathematics of gravity, and modern physics. His school established the four disciplines of arithmetic, geometry, music theory, and astronomy that became the foundation of European university education for a thousand years." },
    { question: "What are Pythagoras's major works?", answer: 'Pythagoras left no surviving written works, and it is debated whether he wrote anything at all. His teachings were transmitted orally within his community and are known through later sources, including the writings of Plato, Aristotle, and various Pythagorean followers.' },
    { question: 'What is the Pythagorean concept that all is number?', answer: "The Pythagorean concept that all is number holds that the fundamental nature of reality is mathematical. Pythagoras and his followers discovered that musical harmonies correspond to precise numerical ratios, such as the octave to 2:1, and generalized this into the claim that all natural phenomena, from planetary motion to the proportions of the human body, exhibit mathematical order that human reason can discover." },
  ],
  'democritus': [
    { question: 'Who was Democritus?', answer: 'Democritus (c. 460–370 BCE) was a Pre-Socratic philosopher known as the "laughing philosopher" for his cheerful disposition. He proposed that all matter is composed of tiny, indivisible, eternal particles called atoms moving through empty space, arriving at this purely materialist worldview through philosophical reasoning alone, 2,400 years before modern atomic theory.' },
    { question: 'What did Democritus believe?', answer: 'Democritus believed that everything that exists is composed of indivisible atoms moving through empty void. He argued that different arrangements of atoms produce different substances, that even the soul is made of atoms, and that there is no supernatural realm, purpose, or design in the universe.' },
    { question: 'Why is Democritus important?', answer: "Democritus arrived at the essential insight of modern atomic physics, that macroscopic properties emerge from the arrangement of microscopic particles, through philosophical reasoning alone. His thoroughgoing materialism and rejection of teleology anticipated the worldview of modern science and directly influenced Epicurus, who built an entire philosophical system on Democritean foundations." },
    { question: "What are Democritus's major works?", answer: 'Democritus was a prolific writer who reportedly produced over seventy works, but none have survived intact. His ideas are known only through fragments and references in later writers, making him one of the most influential philosophers whose original texts have been almost entirely lost.' },
    { question: "What is Democritus's atomic theory?", answer: "Democritus's atomic theory holds that all matter is composed of tiny, indivisible particles called atoms, differing only in shape, size, arrangement, and position, moving through empty void. The qualities we experience, such as color, taste, and temperature, do not exist in the atoms themselves but are produced by the interaction between atomic configurations and our sense organs." },
  ],
  'sextus-empiricus': [
    { question: 'Who was Sextus Empiricus?', answer: 'Sextus Empiricus (c. 160–210 CE) was the most systematic exponent of ancient Pyrrhonian Skepticism. He compiled and refined the arguments of the skeptical tradition into a rigorous philosophical method, and his works, rediscovered during the Renaissance, forced modern philosophers to confront the challenge of radical skepticism.' },
    { question: 'What did Sextus Empiricus believe?', answer: 'Sextus Empiricus argued that for every argument there exists an equal counter-argument and that we should therefore suspend judgment on all matters concerning the hidden nature of things. He taught that this suspension of judgment, rather than the discovery of truth, leads to tranquility of mind.' },
    { question: 'Why is Sextus Empiricus important?', answer: "Sextus Empiricus catalyzed modern philosophy when his works were rediscovered during the Renaissance. Montaigne drew heavily on his arguments, and the skeptical crisis he provoked forced Descartes to develop his method of doubt, Hume his empiricism, and Kant his critical philosophy, making him a pivotal figure in the history of epistemology." },
    { question: "What are Sextus Empiricus's major works?", answer: "Sextus Empiricus's two major surviving works are the Outlines of Pyrrhonism, which provides a systematic overview of Pyrrhonian skeptical methods and arguments, and Against the Mathematicians, a detailed critique of the claims to knowledge made by various disciplines including logic, physics, and ethics." },
    { question: 'What is Pyrrhonian skepticism?', answer: 'Pyrrhonian skepticism, as systematized by Sextus Empiricus, is the practice of suspending judgment when equally strong arguments can be made for and against any claim about the nature of reality. Rather than asserting that knowledge is impossible, the Pyrrhonist simply finds that no claim can be settled and discovers that tranquility follows naturally from abandoning the anxious pursuit of certainty.' },
  ],

  'st-augustine': [
    { question: 'Who was St. Augustine?', answer: 'St. Augustine of Hippo (354-430 CE) was a major figure in Western Christianity and philosophy, born in Roman North Africa. After passing through Manichaeism and academic skepticism, he underwent a dramatic conversion to Christianity in 386 CE and became Bishop of Hippo, producing over five million surviving words on theology, philosophy, and biblical interpretation.' },
    { question: 'What did St. Augustine believe?', answer: 'St. Augustine believed that God is the source of all truth and that evil is not a substance but merely the absence of good. He held that the human mind requires divine illumination to grasp eternal truths, and that time itself is a distension of the soul rather than an independent feature of the external world.' },
    { question: 'Why is St. Augustine important?', answer: 'St. Augustine served as the essential bridge between ancient philosophy and medieval thought. He shaped Christian theology, political philosophy, and the Western understanding of interiority, and his ideas about sin, grace, free will, and time influenced thinkers for over a millennium.' },
    { question: "What are St. Augustine's major works?", answer: "St. Augustine's major works include the Confessions, widely considered the first true autobiography in Western literature, and The City of God, which redefined the relationship between Christian faith and political life. He also wrote On Free Choice of the Will, On the Trinity, and On Christian Doctrine." },
    { question: "What is Augustine's privation theory of evil?", answer: "Augustine argued that evil is not an independent substance or force but a privation, an absence of good, much as darkness is the absence of light. On this view, God created all things good, and evil enters the world through the misuse of free will by rational creatures who turn away from God toward lesser goods. This framework became the dominant theodicy in Western thought for over 1,600 years." },
  ],
  'avicenna': [
    { question: 'Who was Avicenna?', answer: 'Avicenna (Ibn Sina, 980-1037 CE) was a Persian polymath born near Bukhara in present-day Uzbekistan. A child prodigy who had memorized the Quran by age ten and mastered medicine by sixteen, he served as court physician and political advisor across the Islamic world while producing two masterworks: The Book of Healing and The Canon of Medicine, both used in European universities for over five centuries.' },
    { question: 'What did Avicenna believe?', answer: 'Avicenna believed that existence and essence are fundamentally distinct, and that everything in the world depends on a Necessary Existent (God) for the fact that it exists. He argued that the universe flows from God through a series of necessary emanations and that self-awareness is more fundamental than bodily awareness, as demonstrated by his Flying Man thought experiment.' },
    { question: 'Why is Avicenna important?', answer: 'Avicenna transmitted and transformed Aristotelian philosophy for both the Islamic world and medieval Europe. His essence-existence distinction became a cornerstone of Thomistic metaphysics, and his Flying Man thought experiment anticipated key arguments about consciousness and personal identity that would not be fully explored again until Descartes.' },
    { question: "What are Avicenna's major works?", answer: "Avicenna's major works include The Book of Healing, a vast philosophical encyclopedia covering logic, physics, mathematics, and metaphysics, and The Canon of Medicine, a systematic medical textbook that remained standard in European universities for centuries. He also wrote the Book of Salvation, a more concise treatment of his philosophical system." },
    { question: "What is Avicenna's Flying Man thought experiment?", answer: "Avicenna's Flying Man asks you to imagine a person created fully formed, suspended in empty space with no sensory contact with the world. Avicenna argued this person would still be aware of their own existence, proving that self-awareness does not depend on the body or the senses. The thought experiment anticipated Descartes' cogito by over six hundred years and remains relevant to modern debates about consciousness and the mind-body problem." },
  ],
  'averroes': [
    { question: 'Who was Averroes?', answer: 'Averroes (Ibn Rushd, 1126-1198 CE) was the greatest Islamic Aristotelian commentator, known in medieval Europe simply as The Commentator. Born in Cordoba, Spain, he produced detailed commentaries on nearly all of Aristotle\'s works and argued that philosophy and religion both seek truth through different but compatible methods.' },
    { question: 'What did Averroes believe?', answer: 'Averroes believed that philosophy and religion are compatible paths to truth, since truth cannot contradict truth. He maintained that when scripture appears to conflict with philosophical demonstration, the scriptural text must be interpreted allegorically. He also argued that the material world is eternal and that there is a single universal intellect shared by all human beings.' },
    { question: 'Why is Averroes important?', answer: 'Averroes\' Aristotle commentaries shaped the entire tradition of European scholasticism, and Thomas Aquinas engaged deeply with his work on nearly every major philosophical question. His Decisive Treatise established an influential framework for reconciling faith and reason that influenced both Islamic and Christian intellectual traditions for centuries.' },
    { question: "What are Averroes' major works?", answer: "Averroes' major works include his extensive Commentaries on Aristotle, which earned him the title The Commentator in medieval Europe. He also wrote The Incoherence of the Incoherence, a systematic rebuttal of Al-Ghazali's attack on philosophy, and the Decisive Treatise, which argued for the compatibility of philosophy and religious law." },
    { question: "What is Averroes' doctrine of the unity of the intellect?", answer: "Averroes proposed that there is only one universal intellect shared by all human beings, rather than each person possessing their own individual intellect. Individual humans connect temporarily to this single intellect during acts of thought, but personal immortality is an illusion since nothing individual survives death. This thesis was condemned by the Church in 1270 and attacked by Thomas Aquinas as his primary philosophical opponent." },
  ],
  'maimonides': [
    { question: 'Who was Maimonides?', answer: 'Maimonides (Moses ben Maimon, 1138-1204 CE) was the foremost medieval Jewish philosopher and a leading Torah scholar. He reconciled Aristotelian philosophy with Jewish theology in his Guide for the Perplexed, codified Jewish law in the Mishneh Torah, and served as a court physician in Egypt.' },
    { question: 'What did Maimonides believe?', answer: 'Maimonides believed that reason and revelation are harmonious and that God is best understood through negative theology, stating what God is not rather than what God is. He argued that when scripture appears to contradict philosophical demonstration, the text must be interpreted allegorically, while also maintaining that human reason has genuine limits it cannot transcend.' },
    { question: 'Why is Maimonides important?', answer: 'Maimonides was the greatest medieval Jewish philosopher, and his work directly influenced Thomas Aquinas, Spinoza, and the broader Jewish intellectual tradition. His method of reconciling faith and reason established a template for rational theology across all three Abrahamic traditions that remains foundational today.' },
    { question: "What are Maimonides' major works?", answer: "Maimonides' major works include the Guide for the Perplexed, written for students caught between their faith and philosophical education, and the Mishneh Torah, a comprehensive codification of Jewish law. He also wrote the Commentary on the Mishnah, which included his influential thirteen principles of Jewish faith." },
    { question: "What is Maimonides' negative theology?", answer: "Maimonides argued that we cannot say what God is, only what God is not, because any positive attribute would limit the infinite. To say God is powerful invites misleading comparison with other powerful things, so the only honest approach is to say God is not ignorant, not powerless, not composite. This sophisticated approach to religious language influenced Aquinas and remains a significant position in philosophy of religion." },
  ],
  'boethius': [
    { question: 'Who was Boethius?', answer: 'Boethius (480-524 CE) was a Roman philosopher, statesman, and translator known as the last Roman and first Scholastic. He translated Aristotle\'s logical works into Latin, preserving them for the medieval West, and while imprisoned and sentenced to death by the Ostrogothic king Theodoric, he wrote The Consolation of Philosophy, one of the most widely read books of the Middle Ages.' },
    { question: 'What did Boethius believe?', answer: 'Boethius believed that true happiness lies in the contemplation of God, not in external goods like wealth, power, or fame, since Fortune is fickle and can take them away at any moment. He also argued that divine foreknowledge is compatible with human free will because God exists outside of time entirely, seeing all moments in an eternal present.' },
    { question: 'Why is Boethius important?', answer: 'Boethius transmitted Aristotle\'s logic to medieval Europe, providing the foundation of logical education in the West for the next seven centuries. His Consolation of Philosophy influenced Dante, Chaucer, and Aquinas, and was translated by King Alfred and Queen Elizabeth I. His framing of the universals problem set the agenda for medieval metaphysics.' },
    { question: "What are Boethius' major works?", answer: "Boethius' most famous work is The Consolation of Philosophy, a dialogue with Lady Philosophy about fate, free will, and true happiness, written while he awaited execution. His translations of and commentaries on Aristotle's logical works, including the Categories and On Interpretation, formed the entire logical curriculum of Western education from roughly 500 to 1100 CE." },
    { question: "What is Boethius' solution to the problem of divine foreknowledge and free will?", answer: "Boethius argued that God does not foreknow the future the way humans predict events, because God is eternal and exists outside time altogether. God sees all of time at once in an eternal present, much as a person on a hilltop sees the entire road below. Just as watching someone walk does not cause them to walk, God's seeing our choices does not cause us to make them, preserving genuine human freedom." },
  ],
  'al-ghazali': [
    { question: 'Who was Al-Ghazali?', answer: 'Al-Ghazali (1058-1111 CE) was the most influential Muslim thinker after the Prophet Muhammad. He rose to become the most prestigious professor at the Nizamiyyah madrasa in Baghdad before suffering a spiritual crisis that led him to abandon his position and spend over a decade as a wandering Sufi mystic seeking direct experience of God.' },
    { question: 'What did Al-Ghazali believe?', answer: 'Al-Ghazali believed that philosophical reasoning alone cannot reach ultimate truth and that genuine knowledge requires mystical experience. He argued that what we call natural causation is actually God directly creating each event, and that the highest truths are accessed not through argument but through direct spiritual experience he called tasting (dhawq).' },
    { question: 'Why is Al-Ghazali important?', answer: 'Al-Ghazali reshaped Islamic thought by establishing the limits of philosophy and the primacy of religious experience. His Incoherence of the Philosophers mounted a systematic attack on the Islamic Aristotelian tradition, provoking Averroes\' famous counter-attack and defining the intellectual landscape of the Islamic Golden Age.' },
    { question: "What are Al-Ghazali's major works?", answer: "Al-Ghazali's major works include The Incoherence of the Philosophers, a systematic dismantling of twenty key propositions held by Islamic Aristotelians. His Revival of the Religious Sciences sought to reunify Islamic law, theology, and Sufi mysticism. His intellectual autobiography, Deliverance from Error, vividly recounts his journey through philosophical doubt to spiritual certainty." },
    { question: "What is Al-Ghazali's critique of causation?", answer: "Al-Ghazali argued that when fire touches cotton and the cotton burns, we observe only a regular sequence of events, not a necessary connection between them. God, he contended, is the only true cause and directly creates each event, choosing to produce burning each time fire meets cotton. This argument anticipated David Hume's famous critique of causation by over six centuries and remains central to debates about the nature of scientific laws." },
  ],
  'thomas-aquinas': [
    { question: 'Who was Thomas Aquinas?', answer: 'Thomas Aquinas (1225-1274) was an Italian Dominican friar and the central philosopher-theologian of the Western tradition. Nicknamed the Dumb Ox by classmates for his large frame and quiet manner, he produced the Summa Theologica, a systematic synthesis of Christian revelation with Aristotelian philosophy that remains the official intellectual framework of the Catholic Church.' },
    { question: 'What did Thomas Aquinas believe?', answer: 'Thomas Aquinas believed that faith and reason are complementary paths to truth, like two wings on which the mind rises. He held that God\'s existence is demonstrable through rational argument, that natural law provides a universal moral standard accessible to all rational beings, and that grace perfects nature rather than destroying it.' },
    { question: 'Why is Thomas Aquinas important?', answer: 'Thomas Aquinas is the official philosopher of the Catholic Church, and his synthesis of faith and reason shaped Western intellectual history. His Five Ways remain the starting point for serious philosophical discussion of theism, and his natural law theory influenced international law, the concept of human rights, and continues to shape legal and political philosophy.' },
    { question: "What are Thomas Aquinas' major works?", answer: "Thomas Aquinas' masterwork is the Summa Theologica, a systematic synthesis of theology and philosophy left unfinished at over 1.5 million words. He also wrote the Summa Contra Gentiles, aimed at those outside the Christian tradition, On Being and Essence, a concise metaphysical treatise, and numerous Disputed Questions on specific philosophical topics." },
    { question: "What are Aquinas' Five Ways?", answer: "Aquinas' Five Ways are five rational arguments for God's existence, each starting from an observable feature of the world. They argue from motion to an Unmoved Mover, from causation to a First Cause, from contingency to a Necessary Being, from degrees of perfection to a Most Perfect Being, and from the order of nature to an Intelligent Director. Each argument is meant to be independent, so even if some fail, others may succeed." },
  ],
  'william-of-ockham': [
    { question: 'Who was William of Ockham?', answer: 'William of Ockham (1287-1347) was an English Franciscan friar whose nominalism and logical rigor challenged the dominant Scholastic tradition. His famous razor, the principle of parsimony, became a foundational tool of scientific reasoning, and he also wrote extensively on political philosophy, defending the separation of church and state.' },
    { question: 'What did William of Ockham believe?', answer: 'William of Ockham believed that entities should not be multiplied beyond necessity, meaning the simplest explanation is preferable. He held that only individual, particular things exist and that universals like redness or humanity are merely names the mind applies to similar individuals, not real things existing independently in the world.' },
    { question: 'Why is William of Ockham important?', answer: 'William of Ockham\'s razor principle shaped the scientific revolution by providing a standing corrective against unnecessary theoretical complexity. His nominalism influenced the development of empiricism and analytic philosophy by redirecting attention from abstract universals to concrete, observable particulars, helping create the intellectual conditions for modern science.' },
    { question: "What are William of Ockham's major works?", answer: "William of Ockham's major works include the Summa Logicae, a comprehensive treatise on logic that applied his nominalist principles. He also wrote the Quodlibetal Questions, addressing a wide range of philosophical and theological topics, and the Dialogus, a major work on political philosophy defending the separation of church and state." },
    { question: "What is Ockham's Razor?", answer: "Ockham's Razor is the principle that entities should not be multiplied beyond necessity, meaning that when two theories explain the same phenomena equally well, you should prefer the one that makes fewer assumptions. It is a methodological tool for disciplining thought, not a claim that simpler theories are always true. The principle became foundational to scientific method and remains central to rational inquiry across disciplines." },
  ],
  'anselm-of-canterbury': [
    { question: 'Who was Anselm of Canterbury?', answer: 'Anselm of Canterbury (1033-1109) was a Benedictine monk who became Archbishop of Canterbury and one of the most original thinkers of the medieval period. Born in Aosta in northern Italy, he entered the monastery of Bec in Normandy and produced philosophical works that combined rigorous logical argument with deep personal piety.' },
    { question: 'What did Anselm of Canterbury believe?', answer: 'Anselm of Canterbury believed that God is that than which nothing greater can be conceived, and that God\'s existence can be proven from this concept alone. He held that faith comes first but obligates the believer to seek rational understanding, captured in his motto fides quaerens intellectum (faith seeking understanding).' },
    { question: 'Why is Anselm of Canterbury important?', answer: 'Anselm of Canterbury established the scholastic method of reasoning from faith that dominated European universities for centuries. His ontological argument for God\'s existence has been debated for nearly a thousand years, attracting critiques from Aquinas and Kant and revivals by Godel and Plantinga, making it a permanent fixture of Western philosophy.' },
    { question: "What are Anselm of Canterbury's major works?", answer: "Anselm of Canterbury's major works include the Proslogion, which contains his famous ontological argument for God's existence, and the Monologion, an earlier meditation on the divine attributes. He also wrote Cur Deus Homo, which developed the satisfaction theory of atonement, and De Veritate, a dialogue on the nature of truth." },
    { question: "What is Anselm's ontological argument?", answer: "Anselm's ontological argument begins with the definition of God as that than which nothing greater can be conceived. If such a being existed only in the mind and not in reality, we could conceive of something greater, namely one that also exists in reality, which contradicts the definition. Therefore, God must exist in reality. The argument derives God's existence from the very concept of God, using pure reason alone without appeal to experience or authority." },
  ],
  'hildegard-of-bingen': [
    { question: 'Who was Hildegard of Bingen?', answer: 'Hildegard of Bingen (1098-1179) was a Benedictine abbess, mystic, composer, natural historian, and polymath of the medieval world. She experienced visions from the age of three, composed over 70 liturgical songs, wrote medical and scientific treatises, and was declared a Doctor of the Church in 2012.' },
    { question: 'What did Hildegard of Bingen believe?', answer: 'Hildegard of Bingen believed that the human being stands at the center of creation as a microcosm reflecting the entire universe. She taught that a divine creative energy called viriditas (greenness) flows through all living things, linking the spiritual health of humanity directly to the health of the natural world.' },
    { question: 'Why is Hildegard of Bingen important?', answer: 'Hildegard of Bingen was the most prominent female intellectual of the medieval period, producing an extraordinary body of work spanning theology, cosmology, medicine, music, and ethics. Her visionary theology demonstrated that the boundaries of medieval philosophy were wider than the university-based scholastic tradition, and she was declared a Doctor of the Church in 2012.' },
    { question: "What are Hildegard of Bingen's major works?", answer: "Hildegard of Bingen's major works include Scivias, her first visionary theological work, and Liber Divinorum Operum, her most elaborate account of the cosmos and the human being's place within it. She also wrote Physica, a natural history treatise, the Ordo Virtutum, the earliest known morality play, and Liber Vitae Meritorum on ethics and the virtues." },
    { question: "What is Hildegard's concept of viriditas?", answer: "Viriditas, meaning greenness or greening power, is Hildegard's concept of a divine creative energy that flows through all living things, sustaining growth, fertility, and vitality throughout creation. When human beings live in harmony with God and nature, viriditas flourishes; when they sin, it withers. The concept links spiritual health directly to ecological health and has been recognized as one of the earliest articulations of the idea that human moral failure has environmental consequences." },
  ],
  'peter-abelard': [
    { question: 'Who was Peter Abelard?', answer: 'Peter Abelard (1079-1142) was the dominant and most controversial philosopher of the 12th century, a charismatic lecturer who drew thousands of students to Paris. Despite a turbulent personal life, including his famous love affair with Heloise and condemnation by two Church councils, he essentially created the scholastic method of disputation that dominated European universities for the next three centuries.' },
    { question: 'What did Peter Abelard believe?', answer: 'Peter Abelard believed that understanding must precede genuine belief, and that the morality of an act depends entirely on the agent\'s intention rather than the external action or its consequences. He held that universals exist as concepts in the mind grounded in real similarities among things, staking out a middle path between realism and nominalism.' },
    { question: 'Why is Peter Abelard important?', answer: 'Peter Abelard created the scholastic method of disputation that structured intellectual life in European universities for centuries, directly influencing Aquinas, Scotus, and Ockham. His ethics of intention anticipated Kant\'s focus on the good will, and his conceptualism offered a sophisticated middle ground in the universals debate that influenced subsequent medieval thought.' },
    { question: "What are Peter Abelard's major works?", answer: "Peter Abelard's major works include Sic et Non, which collected 158 theological questions with apparently contradictory authorities on each side, establishing the template for scholastic disputation. He also wrote Scito Te Ipsum (Know Thyself), his treatise on the ethics of intention, Logica Ingredientibus on logic, and Historia Calamitatum, an autobiography recounting his personal misfortunes." },
    { question: "What is Abelard's ethics of intention?", answer: "Abelard argued that the morality of an act depends entirely on the agent's intention, not on the external action or its consequences. A person who unknowingly serves poisoned food is not guilty of murder, while a person who intends to kill but fails is morally guilty. Sin consists not in desire or action but in consciously consenting to what you know to be wrong. This internalization of morality anticipated Kant's focus on the good will by over six centuries." },
  ],
  'niccolo-machiavelli': [
    { question: 'Who was Niccolo Machiavelli?', answer: 'Niccolo Machiavelli (1469-1527) was a senior diplomat and political official of the Florentine Republic who was arrested, tortured, and exiled when the Medici family overthrew the republic in 1512. In forced retirement, he produced The Prince and the Discourses on Livy, becoming the first political thinker to systematically analyze power and human nature on their own terms without filtering them through Christian morality.' },
    { question: 'What did Niccolo Machiavelli believe?', answer: 'Niccolo Machiavelli believed that effective governance requires pragmatism and that a leader must learn how not to be good when circumstances demand it. He argued that political success depends on the interplay between virtu (the leader\'s skill and adaptability) and fortuna (luck and circumstance), and that well-ordered republics are stronger and more just than principalities.' },
    { question: 'Why is Niccolo Machiavelli important?', answer: 'Niccolo Machiavelli founded modern political science by insisting that politics be analyzed as it actually operates rather than as we wish it were. His separation of political effectiveness from personal morality influenced realist traditions in international relations and statecraft, and his republican thought influenced the American founders, particularly the Federalist Papers.' },
    { question: "What are Niccolo Machiavelli's major works?", answer: "Niccolo Machiavelli's most famous work is The Prince, a concise analysis of how political power is acquired and maintained. His longer and more systematic Discourses on Livy analyzes the Roman Republic and reveals a committed republican thinker. He also wrote The Art of War and the Florentine Histories." },
    { question: "What did Machiavelli mean by 'the ends justify the means'?", answer: "While Machiavelli never used that exact phrase, The Prince argues that a ruler must be willing to commit moral wrongs when the survival and welfare of the state require it, what Machiavelli called entering into evil when necessity commands. He distinguished between cruelty well used, applied decisively and not escalated beyond what is needed, and cruelty badly used. The tension he identified between what morality demands and what political responsibility requires has defined debates about political ethics ever since." },
  ],
  'erasmus': [
    { question: 'Who was Erasmus?', answer: 'Desiderius Erasmus (1469-1536) was the most influential humanist scholar of the Northern Renaissance and the most famous intellectual in sixteenth-century Europe. His satirical In Praise of Folly critiqued church corruption, while his scholarly editions of the Greek New Testament and the Church Fathers reformed theological study across Europe.' },
    { question: 'What did Erasmus believe?', answer: 'Erasmus believed that true wisdom combines classical learning with Christian virtue, and that peace and tolerance surpass dogma. He argued that the works of Greek and Roman antiquity enhance and deepen Christian faith rather than threatening it, and that education in the humanities produces wiser, more virtuous human beings.' },
    { question: 'Why is Erasmus important?', answer: 'Erasmus was the most important Northern Renaissance humanist, and his influence on education, theology, and tolerance was lasting. His Greek New Testament laid the textual foundation for the Protestant Reformation, and his conviction that broadly educated citizens are more valuable than narrowly trained technicians remains the philosophical foundation of liberal arts education.' },
    { question: "What are Erasmus' major works?", answer: "Erasmus' most famous work is In Praise of Folly, a satirical masterpiece in which the goddess Folly critiques theologians, monks, and popes. He also wrote the Handbook of a Christian Knight on practical piety, the Adages, a widely read collection of classical proverbs, and the Colloquies, witty dialogues on contemporary issues. His 1516 Greek New Testament was his most consequential scholarly achievement." },
    { question: "What is Erasmus' In Praise of Folly about?", answer: "In Praise of Folly gives the goddess Folly a pulpit from which to praise herself, claiming credit for everything that makes life bearable: love, friendship, pleasure, and comforting self-deception. The satire sharpens as Folly turns to theologians who spin endless distinctions, monks who mistake ritual for piety, and popes who wage wars in Christ's name. The brilliance of the work lies in its deliberate ambiguity, as readers can never be entirely sure whether Folly's praise is genuine or ironic." },
  ],
  'michel-de-montaigne': [
    { question: 'Who was Michel de Montaigne?', answer: 'Michel de Montaigne (1533-1592) was a French nobleman, magistrate, and mayor of Bordeaux who essentially invented the essay as a literary and philosophical form. After retiring to his chateau\'s tower library at age thirty-eight, he spent two decades producing his Essais, three books of increasingly searching self-examination covering everything from cannibals to kidney stones.' },
    { question: 'What did Michel de Montaigne believe?', answer: 'Michel de Montaigne believed that self-examination reveals the limits of human knowledge and the diversity of human experience. He held that human judgment is distorted by custom, emotion, and perspective, and that intellectual humility should lead to tolerance rather than persecution of those who disagree with us.' },
    { question: 'Why is Michel de Montaigne important?', answer: 'Michel de Montaigne invented the essay form and revived ancient Pyrrhonian skepticism, applying it to the religious wars tearing Europe apart. His influence extends from Descartes and Pascal through the empiricist tradition to modern literature and the tradition of philosophical self-examination. His argument that humility should lead to tolerance directly shaped the development of modern liberal thought.' },
    { question: "What are Michel de Montaigne's major works?", answer: "Michel de Montaigne's life work is the Essais (Essays), three books of philosophical reflections composed over two decades. The work contains over 100 essays ranging from brief observations to book-length investigations, including the philosophical centerpiece, the Apology for Raymond Sebond. He also kept a Travel Journal recording his observations during a journey through Germany, Switzerland, and Italy." },
    { question: "What does Montaigne's motto 'Que scay-je' mean?", answer: "Montaigne's motto Que scay-je, meaning What do I know, was not a confession of ignorance but a method of inquiry. He used it to mount a sweeping case against intellectual arrogance, cataloguing the ways human judgment is distorted by custom, emotion, illness, and perspective. His conclusion was not that knowledge is impossible but that we should hold our beliefs with humility, remain open to revision, and resist the temptation to persecute others for disagreeing with us." },
  ],
  'thomas-more': [
    { question: 'Who was Thomas More?', answer: 'Thomas More (1478-1535) was an English lawyer, statesman, and Lord Chancellor who coined the word utopia, literally meaning no place. He was executed for refusing to accept Henry VIII as head of the Church of England, declaring himself the King\'s good servant, but God\'s first.' },
    { question: 'What did Thomas More believe?', answer: 'Thomas More believed that an ideal society requires communal property, religious tolerance, and universal education. He argued through his fictional Utopia that as long as private property exists, wealth will be distributed to the worst people and the majority will live in misery, though the ironic structure of the work leaves his own precise commitments deliberately ambiguous.' },
    { question: 'Why is Thomas More important?', answer: 'Thomas More coined the term utopia and inaugurated the modern tradition of imagining radically different social arrangements as a way of criticizing existing ones. His influence extends through socialist thought and utopian fiction, and his martyrdom established the principle that individual conscience has a higher authority than the commands of the state.' },
    { question: "What are Thomas More's major works?", answer: "Thomas More's most important work is Utopia (1516), which imagines an island society where private property has been abolished and all citizens live in equality. The book operates simultaneously as bold social critique and ironic thought experiment. He also wrote A Dialogue of Comfort Against Tribulation during his imprisonment in the Tower of London." },
    { question: "What is More's Utopia about?", answer: "More's Utopia describes an island society where private property has been abolished, all goods are held in common, citizens work six hours a day, and no one suffers want while others live in luxury. However, the work is deliberately ambiguous: the narrator's name means speaker of nonsense in Greek, and the Utopians also practice slavery and mutual surveillance. More uses this systematic ambiguity to force readers to think for themselves about justice, property, and the limits of social reform." },
  ],
  'francis-bacon': [
    { question: 'Who was Francis Bacon?', answer: 'Francis Bacon (1561-1626) was an English statesman, lawyer, and philosopher who rose to become Lord Chancellor before being convicted of bribery. His philosophical legacy eclipsed his political career: he argued that knowledge must be rebuilt from the ground up through systematic observation, experiment, and inductive reasoning rather than deference to ancient authorities.' },
    { question: 'What did Francis Bacon believe?', answer: 'Francis Bacon believed that knowledge is power, meaning the purpose of understanding nature is the practical improvement of human life rather than mere contemplation. He argued that the human mind is systematically prone to error through what he called the four Idols, and that only rigorous inductive method can overcome these biases and produce reliable knowledge.' },
    { question: 'Why is Francis Bacon important?', answer: 'Francis Bacon laid the philosophical groundwork for empiricism and the scientific method, shaping the scientific revolution and modern experimental practice. His vision of science as a collaborative, institutional enterprise anticipated the modern research university, and the Royal Society was founded partly in his spirit. His four Idols remain a powerful framework for understanding cognitive bias.' },
    { question: "What are Francis Bacon's major works?", answer: "Francis Bacon's most important philosophical work is the Novum Organum, deliberately named to replace Aristotle's Organon as the tool of inquiry, which presents his inductive method and the doctrine of the Idols. He also wrote The Advancement of Learning, a comprehensive survey of human knowledge, New Atlantis, a utopian fiction envisioning a society organized around scientific research, and his Essays on practical wisdom." },
    { question: "What are Bacon's four Idols of the Mind?", answer: "Bacon identified four categories of persistent error that distort human thinking. The Idols of the Tribe are biases built into human nature, such as seeing patterns where none exist and favoring confirming evidence. The Idols of the Cave are individual biases from temperament and education. The Idols of the Marketplace arise from the imprecision of language. The Idols of the Theater are grand systems accepted on authority rather than evidence. Together, they form one of the earliest systematic analyses of cognitive bias." },
  ],
  'giordano-bruno': [
    { question: 'Who was Giordano Bruno?', answer: 'Giordano Bruno (1548-1600) was an Italian Dominican friar, philosopher, and cosmologist who proposed that the universe is infinite, containing innumerable worlds, and that God is immanent in all things. After years of wandering across Europe debating and making enemies, he was arrested by the Inquisition in 1592 and burned at the stake in Rome in 1600 after refusing to recant.' },
    { question: 'What did Giordano Bruno believe?', answer: 'Giordano Bruno believed that the universe is infinite with no edge, no center, and no fixed sphere of stars, and that the stars are distant suns potentially surrounded by inhabited worlds. He held a pantheistic theology arguing that God is not separate from the universe but is the infinite creative force immanent in every particle of matter.' },
    { question: 'Why is Giordano Bruno important?', answer: 'Giordano Bruno\'s vision of an infinite universe anticipated modern cosmology by centuries, and his execution made him a defining martyr for intellectual freedom. His pantheistic identification of God with nature influenced Spinoza\'s philosophy and later Romantic thought, and his statue now stands in the Roman square where he was burned.' },
    { question: "What are Giordano Bruno's major works?", answer: "Giordano Bruno's major works include On the Infinite Universe and Worlds, which argued that the cosmos is boundless and filled with innumerable suns and planets. He also wrote On Cause, Principle, and Unity, developing his pantheistic metaphysics, and The Expulsion of the Triumphant Beast, a moral allegory attacking intellectual complacency." },
    { question: "What is Bruno's theory of the infinite universe?", answer: "Bruno argued that the universe is boundless, with no edge, no center, and no fixed sphere of stars, and that the stars are suns like our own, each potentially surrounded by inhabited worlds. His reasoning was philosophical rather than observational: an infinite God must produce an infinite creation, because anything less would limit divine power and goodness. This vision, proposed before the invention of the telescope, anticipated key features of modern cosmology." },
  ],
  'galileo-galilei': [
    { question: 'Who was Galileo Galilei?', answer: 'Galileo Galilei (1564-1642) was an Italian astronomer, physicist, and philosopher whose telescopic observations and experiments transformed humanity\'s understanding of the cosmos. His work provided decisive evidence for the Copernican heliocentric model, and his insistence on observation and mathematical analysis over authority made him a central figure in the Scientific Revolution.' },
    { question: 'What did Galileo Galilei believe?', answer: 'Galileo Galilei believed that the book of nature is written in the language of mathematics and that observation, not authority, reveals its truths. He held that the true description of reality is mathematical and quantitative, not qualitative, and that no authority, however ancient or revered, can override what nature reveals when properly questioned through experiment.' },
    { question: 'Why is Galileo Galilei important?', answer: 'Galileo Galilei established modern observational astronomy and experimental physics, laying the foundations of modern mechanics through his experiments with falling bodies, inclined planes, and pendulums. His mathematization of nature made modern physics possible, and his empiricism helped launch the Scientific Revolution by establishing that evidence, not authority, is the ultimate arbiter of truth about the physical world.' },
    { question: "What are Galileo Galilei's major works?", answer: "Galileo Galilei's major works include the Dialogue Concerning the Two Chief World Systems, which argued for the Copernican heliocentric model and led to his trial by the Inquisition. His Discourses and Mathematical Demonstrations, written under house arrest, is considered his greatest contribution to physics. He also wrote The Starry Messenger, reporting his telescopic discoveries, and The Assayer, on scientific methodology." },
    { question: "What was the Galileo Affair?", answer: "The Galileo Affair refers to Galileo's trial by the Roman Inquisition in 1633, which has become the defining symbol of conflict between science and religious authority. The deeper issue was not about planetary orbits but about epistemological authority: who has the right to make claims about the physical world. Galileo was forced to recant his support for heliocentrism and spent his remaining years under house arrest, but the affair forced a lasting reckoning with how to handle conflicts between established authority and empirical evidence." },
  ],

  'blaise-pascal': [
    { question: 'Who was Blaise Pascal?', answer: 'Blaise Pascal (1623-1662) was a French mathematician, physicist, and philosopher who made foundational contributions to probability theory, hydraulics, and the physics of the vacuum. A mathematical prodigy who invented one of the first mechanical calculators, he underwent an intense mystical experience in 1654 and devoted his remaining years to philosophy and Christian apologetics, producing the fragmentary Pensees before his death at thirty-nine.' },
    { question: 'What did Blaise Pascal believe?', answer: 'Blaise Pascal believed that reason alone is insufficient to reach the deepest truths about human existence and God. He argued that the heart possesses its own mode of immediate, intuitive knowledge that grasps first principles directly, and that human beings are suspended between two infinities, the infinitely large and the infinitely small, comprehending neither.' },
    { question: 'Why is Blaise Pascal important?', answer: 'Blaise Pascal founded decision theory and the application of probabilistic reasoning to practical life. His Pensees influenced Kierkegaard, existentialism, and philosophy of religion, and his work on probability introduced concepts fundamental to game theory, expected utility, and risk analysis.' },
    { question: "What are Blaise Pascal's major works?", answer: "Blaise Pascal's major works include the Pensees, his unfinished defense of Christianity containing sharp observations on human nature, faith, and the limits of reason. He also wrote the Provincial Letters, a series of polemical letters defending Jansenism against the Jesuits." },
    { question: "What is Pascal's Wager?", answer: "Pascal's Wager is a practical argument for belief in God framed as a decision under uncertainty. Pascal argued that if God exists and you believe, you gain infinite happiness, while if God does not exist, the believer loses very little. Since the expected value of belief dominates, wagering on God is the rational choice. The Wager founded decision theory and remains debated in philosophy of religion and game theory." },
  ],
  'thomas-hobbes': [
    { question: 'Who was Thomas Hobbes?', answer: 'Thomas Hobbes (1588-1679) was an English philosopher who witnessed the English Civil War and concluded that strong government is essential to prevent chaos. He spent years in exile in Paris, served as mathematics tutor to the future Charles II, and produced his masterwork Leviathan in 1651, which became one of the foundational texts of modern political philosophy.' },
    { question: 'What did Thomas Hobbes believe?', answer: 'Thomas Hobbes believed that without government, human life would be a war of all against all, not because people are inherently evil, but because rational self-interest in the absence of enforceable agreements makes cooperation unstable. He argued that people must surrender some freedoms to a sovereign authority in exchange for security and order through a social contract.' },
    { question: 'Why is Thomas Hobbes important?', answer: 'Thomas Hobbes set the terms for modern political philosophy and social contract theory. His insight that rational self-interest without enforcement leads to collective disaster anticipated the Prisoners Dilemma in game theory by three centuries, and every subsequent political thinker from Locke to Rawls has had to respond to his challenge.' },
    { question: "What are Thomas Hobbes's major works?", answer: "Thomas Hobbes's major works include Leviathan, his masterpiece arguing for a strong sovereign to prevent the chaos of the state of nature. He also wrote De Cive on the foundations of political society, De Corpore laying out his materialist metaphysics, and Elements of Law." },
    { question: "What is Hobbes's social contract theory?", answer: "Hobbes's social contract theory holds that in the state of nature, without government, rational self-interest drives everyone toward preemptive aggression, producing universal conflict. The only escape is a mutual agreement in which all parties surrender their freedom to a sovereign authority powerful enough to enforce agreements and punish defection, thereby making peaceful cooperation possible." },
  ],
  'baruch-spinoza': [
    { question: 'Who was Baruch Spinoza?', answer: 'Baruch Spinoza (1632-1677) was a Dutch philosopher of Portuguese Jewish descent who was excommunicated from his Jewish community at age twenty-three for his radical ideas. Working as a lens grinder, he developed an all-encompassing philosophical system presented in geometric form with axioms and proofs in his masterwork, the Ethics.' },
    { question: 'What did Baruch Spinoza believe?', answer: 'Baruch Spinoza believed that God and Nature are one and the same infinite substance, a position known as pantheism. He argued that free will is an illusion caused by our ignorance of the causes that determine our actions, and that genuine freedom comes through rational understanding of reality rather than through uncaused choice.' },
    { question: 'Why is Baruch Spinoza important?', answer: 'Baruch Spinoza influenced German Idealism, Romanticism, and contemporary philosophy of mind, and has been called the prince of philosophers. Albert Einstein famously said he believed in Spinoza\'s God, and Spinoza\'s naturalistic approach to ethics and his deterministic view of the mind anticipated modern neuroscience and psychotherapy.' },
    { question: "What are Baruch Spinoza's major works?", answer: "Baruch Spinoza's major works include the Ethics, his masterpiece composed in geometric form arguing that God is identical with Nature. He also wrote the Theological-Political Treatise defending freedom of thought and religion, and On the Improvement of the Understanding on philosophical method." },
    { question: "What is Spinoza's concept of God as Nature?", answer: "Spinoza's concept of Deus sive Natura (God or Nature) holds that God is not a transcendent creator separate from the world but is identical with Nature itself, one infinite substance expressing itself through infinite attributes. Everything that exists is a mode or expression of this single substance, and the laws of nature are identical with the power of God." },
  ],
  'john-locke': [
    { question: 'Who was John Locke?', answer: 'John Locke (1632-1704) was an English philosopher and physician who became the personal doctor and political advisor to the Earl of Shaftesbury. When Shaftesbury fell from power, Locke fled to Holland, where he wrote his two greatest works. His Two Treatises of Government and Essay Concerning Human Understanding directly shaped modern democracy and empiricist philosophy.' },
    { question: 'What did John Locke believe?', answer: 'John Locke believed that all people are by nature free, equal, and independent, and that government derives its authority solely from the consent of the governed. He argued that the mind at birth is a blank slate, that all knowledge derives from experience, and that individuals possess natural rights to life, liberty, and property that no government may legitimately violate.' },
    { question: 'Why is John Locke important?', answer: 'John Locke gave classical liberalism its philosophical vocabulary and supplied the intellectual framework for the American founding. Jefferson called Locke one of the three greatest men who have ever lived, and the Declaration of Independence, the Constitution, and the Bill of Rights all draw directly on his natural rights philosophy.' },
    { question: "What are John Locke's major works?", answer: "John Locke's major works include the Two Treatises of Government, which provided the philosophical foundation for constitutional democracy and natural rights. His Essay Concerning Human Understanding established empiricism as a major philosophical tradition, and A Letter Concerning Toleration laid the groundwork for religious freedom." },
    { question: "What is Locke's blank slate (tabula rasa) theory?", answer: "Locke's blank slate theory holds that the mind at birth is empty of all ideas, and that all knowledge comes from two sources: sensation (experience of the external world through our senses) and reflection (the mind observing its own operations). This means there are no innate moral principles or innate ideas of God, and that education and environment have enormous power to shape who we become." },
  ],
  'gottfried-wilhelm-leibniz': [
    { question: 'Who was Gottfried Wilhelm Leibniz?', answer: 'Gottfried Wilhelm Leibniz (1646-1716) was a German philosopher, mathematician, diplomat, and inventor who independently developed calculus, pioneered binary arithmetic, and designed calculating machines. He produced an elaborate metaphysical system centered on immaterial substances called monads and is known for his optimistic claim that this is the best of all possible worlds.' },
    { question: 'What did Gottfried Wilhelm Leibniz believe?', answer: 'Gottfried Wilhelm Leibniz believed that reality consists of infinite simple, immaterial substances called monads, each mirroring the entire universe from its own unique perspective. He held that nothing exists or occurs without a sufficient reason, and that God, being omniscient and perfectly good, created the best of all logically possible worlds.' },
    { question: 'Why is Gottfried Wilhelm Leibniz important?', answer: 'Gottfried Wilhelm Leibniz co-invented calculus and made foundational contributions to logic, computer science, and analytic philosophy. His monadology anticipated aspects of information theory, his rejection of purely mechanical materialism influenced German Idealism and process philosophy, and his principle of sufficient reason remains central to metaphysics and philosophy of religion.' },
    { question: "What are Gottfried Wilhelm Leibniz's major works?", answer: "Gottfried Wilhelm Leibniz's major works include the Monadology, which presents his theory that reality consists of immaterial perceiving substances. His Theodicy addresses the problem of evil, the Discourse on Metaphysics outlines his core philosophical positions, and the New Essays on Human Understanding responds to Locke's empiricism." },
    { question: "What are Leibniz's monads?", answer: "Leibniz's monads are the ultimate constituents of reality: simple, immaterial substances that have no spatial parts and cannot interact causally with one another. Each monad mirrors the entire universe from its own unique perspective, and God established a pre-established harmony at creation so that every monad's internal development corresponds perfectly with every other's, like clocks synchronized by a master clockmaker." },
  ],
  'george-berkeley': [
    { question: 'Who was George Berkeley?', answer: 'George Berkeley (1685-1753) was an Irish philosopher and Anglican bishop who published his major philosophical work at age twenty-five. He pushed empiricism to a startling conclusion by arguing that physical objects do not exist independently of minds, a position known as immaterialism or idealism.' },
    { question: 'What did George Berkeley believe?', answer: 'George Berkeley believed that to be is to be perceived (esse est percipi), meaning that physical objects are nothing more than collections of ideas in minds. He argued that matter does not exist independently of perception, and that the continuous existence of the physical world is sustained by the ever-present mind of God.' },
    { question: 'Why is George Berkeley important?', answer: 'George Berkeley\'s idealism forced every subsequent empiricist to explain how we can justify belief in a mind-independent material world. His arguments influenced Hume, Kant, phenomenology, and the entire tradition of philosophy of perception, and the challenge he raised has never been fully resolved.' },
    { question: "What are George Berkeley's major works?", answer: "George Berkeley's major works include A Treatise Concerning the Principles of Human Knowledge, which argues that physical objects exist only as collections of perceptions in minds. His Three Dialogues between Hylas and Philonous presents the same arguments in a more accessible dialogue format." },
    { question: "What does Berkeley's 'to be is to be perceived' mean?", answer: "Berkeley's principle esse est percipi holds that physical objects do not exist independently of minds. What we call an apple is not a material substance lurking behind our perceptions but is the collection of perceptions itself: a certain color, taste, smell, and texture. Take away all the sensory qualities and nothing remains, making the notion of unperceived matter incoherent." },
  ],
  'rene-descartes': [
    { question: 'Who was Rene Descartes?', answer: 'Rene Descartes (1596-1650) was a French mathematician, scientist, and philosopher who spent most of his productive career in the Dutch Republic. He invented analytic geometry, made contributions to optics and physiology, and produced the Meditations on First Philosophy, which remains a touchstone of modern philosophy and the first text assigned in most philosophy courses.' },
    { question: 'What did Rene Descartes believe?', answer: 'Rene Descartes believed that the path to genuine knowledge requires systematically doubting every belief until reaching something absolutely certain. He discovered that the one indubitable truth is the existence of the thinking self, and he argued that mind and body are fundamentally different kinds of substance.' },
    { question: 'Why is Rene Descartes important?', answer: 'Rene Descartes set the starting point for modern epistemology and created the framework for modern philosophy of mind. His method of systematic doubt, his proof of the thinking self, and his sharp separation of mind from body set the agenda for three centuries of philosophy and continue to shape debates about consciousness and artificial intelligence.' },
    { question: "What are Rene Descartes's major works?", answer: "Rene Descartes's major works include the Meditations on First Philosophy, which establishes the cogito and mind-body dualism through systematic doubt. He also wrote the Discourse on the Method, Principles of Philosophy, and Rules for the Direction of the Mind, all addressing how to achieve certain knowledge." },
    { question: "What is Descartes' 'I think, therefore I am'?", answer: "Descartes' cogito ergo sum is the conclusion of his method of radical doubt. After doubting everything he possibly could, including his senses, the external world, and even mathematics, Descartes discovered that the very act of doubting proves there is something doing the doubting. Even if an evil demon deceives him about everything else, it cannot deceive him about his own existence, because to be deceived he must exist." },
  ],
  'david-hume': [
    { question: 'Who was David Hume?', answer: 'David Hume (1711-1776) was a Scottish philosopher, historian, and essayist who conceived his philosophical masterwork, A Treatise of Human Nature, while still in his early twenties during a period of intense study in France. Though his philosophical work was initially ignored, his reputation grew enormously after his death, and Kant credited Hume with awakening him from his dogmatic slumber.' },
    { question: 'What did David Hume believe?', answer: 'David Hume believed that all knowledge derives from experience and that reason alone cannot establish matters of fact. He argued that our belief in causation has no rational basis but rests on custom and habit, that moral judgments arise from sentiment rather than reason, and that there is a logical gap between factual claims and moral prescriptions.' },
    { question: 'Why is David Hume important?', answer: 'David Hume awakened Kant from his dogmatic slumber and provoked one of the greatest revolutions in the history of philosophy. His problem of induction remains unsolved, his critique of causation reshaped metaphysics, and his sentimentalist approach to ethics has experienced a major revival in contemporary moral psychology.' },
    { question: "What are David Hume's major works?", answer: "David Hume's major works include A Treatise of Human Nature, his ambitious early masterpiece on epistemology, ethics, and the passions. He also wrote An Enquiry Concerning Human Understanding, An Enquiry Concerning the Principles of Morals, and the posthumous Dialogues Concerning Natural Religion." },
    { question: "What is Hume's problem of induction?", answer: "Hume's problem of induction is the challenge that we cannot rationally justify our belief that the future will resemble the past. Our confidence in natural regularities rests on the assumption that patterns will continue, but that assumption is itself based on past experience, creating circular reasoning. Hume concluded that our belief in causation is grounded in psychological habit rather than logical demonstration, a problem that remains unsolved." },
  ],
  'jean-jacques-rousseau': [
    { question: 'Who was Jean-Jacques Rousseau?', answer: 'Jean-Jacques Rousseau (1712-1778) was a Genevan philosopher, writer, and composer whose radical ideas on nature, society, and politics made him one of the most polarizing figures of the Enlightenment. His works were frequently banned and publicly burned, and he spent years in exile, yet his ideas profoundly shaped the French Revolution, Romanticism, and modern democratic theory.' },
    { question: 'What did Jean-Jacques Rousseau believe?', answer: 'Jean-Jacques Rousseau believed that humans are naturally good but corrupted by society, and that civilization itself, through private property and social comparison, creates artificial needs and inequality. He argued that legitimate government requires the general will of the people and that education should follow nature rather than imposing adult categories on children.' },
    { question: 'Why is Jean-Jacques Rousseau important?', answer: 'Jean-Jacques Rousseau directly influenced the French Revolution, Romanticism, and progressive education. His critique of civilization anticipated Marx\'s theory of alienation and contemporary critiques of social media, and his child-centered educational philosophy inspired Pestalozzi, Montessori, and Dewey.' },
    { question: "What are Jean-Jacques Rousseau's major works?", answer: "Jean-Jacques Rousseau's major works include The Social Contract, which argues that legitimate government rests on the general will. His Discourse on Inequality traces how civilization corrupts natural goodness, Emile revolutionized educational philosophy, and the Confessions pioneered the modern autobiography." },
    { question: "What is Rousseau's general will?", answer: "Rousseau's general will is the common interest of all citizens considered as a collective body, distinct from the mere aggregate of individual preferences. Laws must reflect what is best for the community as a whole, not what any individual or faction desires. Rousseau argued that citizens who refuse to obey the general will may be forced to be free, a concept that has been both celebrated as the foundation of democratic theory and criticized as containing authoritarian potential." },
  ],
  'voltaire': [
    { question: 'Who was Voltaire?', answer: 'Voltaire (1694-1778), born Francois-Marie Arouet, was a French writer, philosopher, and the Enlightenment\'s most famous public intellectual. A relentless critic of religious intolerance, censorship, and tyranny, he was imprisoned in the Bastille, exiled to England, and spent much of his life in conflict with authorities while producing an enormous body of satirical and philosophical work.' },
    { question: 'What did Voltaire believe?', answer: 'Voltaire believed in crushing fanaticism and championing reason, tolerance, and freedom of thought and expression. He argued that religious intolerance is both morally monstrous and practically destructive, that speculative metaphysics should yield to practical action to reduce suffering, and that societies thrive when they embrace intellectual freedom and limit religious and political power.' },
    { question: 'Why is Voltaire important?', answer: 'Voltaire was the Enlightenment\'s sharpest satirist and a tireless advocate for tolerance, free speech, and secular governance. His intervention in the Calas affair established a model of public intellectual activism, and his Philosophical Letters helped introduce Newtonian physics and Lockean empiricism to the French public, shaping the intellectual climate that produced the French Revolution.' },
    { question: "What are Voltaire's major works?", answer: "Voltaire's major works include Candide, his devastating satire of philosophical optimism. The Philosophical Letters introduced English ideas of tolerance and liberty to France, the Philosophical Dictionary challenged religious and political orthodoxy, and the Treatise on Tolerance made the case for religious freedom." },
    { question: "What is the message of Voltaire's Candide?", answer: "Voltaire's Candide satirizes the philosophical optimism of Leibniz, who argued this is the best of all possible worlds. Through an escalating series of disasters suffered by the naive hero, Voltaire demonstrates the moral bankruptcy of any philosophy that explains away mass suffering as part of a rational cosmic design. The novel concludes that the proper response to suffering is not philosophical explanation but practical action to improve what is within our reach." },
  ],
  'immanuel-kant': [
    { question: 'Who was Immanuel Kant?', answer: 'Immanuel Kant (1724-1804) was a German philosopher who spent his entire life in Konigsberg, East Prussia, yet produced a philosophical revolution that reshaped every branch of the discipline. His three Critiques, published when he was in his fifties and sixties, form the most ambitious and systematic philosophical project since Aristotle.' },
    { question: 'What did Immanuel Kant believe?', answer: 'Immanuel Kant believed that the mind actively structures all experience according to its own innate categories, meaning we never experience reality as it is in itself. He argued that morality must be grounded in universal rational duty rather than consequences or feelings, and that pure reason, when it tries to go beyond possible experience, falls into inevitable contradictions.' },
    { question: 'Why is Immanuel Kant important?', answer: 'Immanuel Kant\'s critical philosophy reshaped every area of the discipline and set the agenda for two centuries of debate. His categorical imperative remains the dominant deontological ethical framework, his concept of human dignity underlies modern human rights law, and his transcendental idealism resolved the central debate between rationalism and empiricism.' },
    { question: "What are Immanuel Kant's major works?", answer: "Immanuel Kant's major works include the Critique of Pure Reason, which examines the limits and structure of human knowledge. The Critique of Practical Reason addresses morality, the Groundwork of the Metaphysics of Morals presents the categorical imperative, and the Critique of Judgment treats aesthetics and teleology." },
    { question: "What is Kant's categorical imperative?", answer: "Kant's categorical imperative is his supreme moral principle, stating that you should act only according to a maxim that you could rationally will to become a universal law for everyone. A second formulation holds that you must always treat humanity, whether in yourself or others, as an end in itself and never merely as a means. Both express the insight that rational beings have absolute worth and must never be treated as disposable." },
  ],
  'montesquieu': [
    { question: 'Who was Montesquieu?', answer: 'Montesquieu (1689-1755), born Charles-Louis de Secondat, Baron de Montesquieu, was a French judge and political philosopher whose comparative study of governments influenced every modern constitution. After an extended visit to England in 1729-1731, he spent twenty years researching and composing his masterwork, The Spirit of the Laws.' },
    { question: 'What did Montesquieu believe?', answer: 'Montesquieu believed that political liberty can exist only where governmental power is divided among three independent branches: the legislative, the executive, and the judicial. He argued that laws should not be derived from abstract principles alone but must be adapted to the specific conditions of each society, including its climate, geography, religion, and customs.' },
    { question: 'Why is Montesquieu important?', answer: 'Montesquieu is the philosophical architect of constitutional government. His separation of powers was incorporated virtually intact by the framers of the U.S. Constitution, with Madison, Hamilton, and Jefferson all citing The Spirit of the Laws, and has been adopted by every modern democratic constitution. He also invented comparative political sociology.' },
    { question: "What are Montesquieu's major works?", answer: "Montesquieu's major works include The Spirit of the Laws, his comprehensive study of legal and political systems arguing for the separation of powers. His earlier Persian Letters used the device of Persian travelers visiting Paris to satirize French society and expose the absurdities of both Western and Eastern customs." },
    { question: "What is Montesquieu's separation of powers?", answer: "Montesquieu's separation of powers holds that political liberty requires dividing governmental authority among three independent branches: the legislative (which makes laws), the executive (which enforces them), and the judicial (which interprets them). When any two of these powers are united in the same person or body, liberty is destroyed. Each branch must be able to check the others so that power checks power." },
  ],
  'adam-smith': [
    { question: 'Who was Adam Smith?', answer: 'Adam Smith (1723-1790) was a Scottish moral philosopher and economist whose two major works laid the foundations for modern economics and moral psychology. He was first and foremost a moral philosopher, and he considered his Theory of Moral Sentiments a more accomplished work than The Wealth of Nations, revising it until the year of his death.' },
    { question: 'What did Adam Smith believe?', answer: 'Adam Smith believed that moral life is grounded in sympathy, our natural ability to imaginatively enter into the feelings of others, and that free markets can channel self-interest toward public benefit through the price system. He held that economic arrangements must always be evaluated within the moral framework of sympathy and justice.' },
    { question: 'Why is Adam Smith important?', answer: 'Adam Smith laid the groundwork for modern economics with The Wealth of Nations and provided a psychologically realistic account of moral judgment in The Theory of Moral Sentiments. His concept of the invisible hand and his analysis of the division of labor shaped two centuries of economic thought, while his impartial spectator anticipated key ideas in behavioral economics and moral psychology.' },
    { question: "What are Adam Smith's major works?", answer: "Adam Smith's major works include The Theory of Moral Sentiments, which grounds morality in our natural capacity for sympathy and introduces the concept of the impartial spectator. The Wealth of Nations examines how free markets, the division of labor, and self-interest channeled through competition produce prosperity." },
    { question: "What is Adam Smith's invisible hand?", answer: "Adam Smith's invisible hand is the observation that individuals pursuing their own economic interests in a competitive market often promote the public good more effectively than if they had consciously intended to. The price system coordinates millions of independent decisions without central direction. However, Smith emphasized that this mechanism works only under specific institutional conditions, including enforceable contracts, impartial courts, and the absence of monopoly." },
  ],
  'jeremy-bentham': [
    { question: 'Who was Jeremy Bentham?', answer: 'Jeremy Bentham (1748-1832) was an English philosopher and reformer who gave utilitarianism its first systematic formulation. A child prodigy who entered Oxford at twelve, he devoted his life to reforming every institution he encountered, from prisons to voting systems. His preserved skeleton still sits in a glass case at University College London.' },
    { question: 'What did Jeremy Bentham believe?', answer: 'Jeremy Bentham believed that the right action, law, or policy is the one that produces the greatest total happiness for all those affected. He held that nature has placed mankind under the governance of two sovereign masters, pain and pleasure, and that every person\'s happiness counts equally in the moral calculus.' },
    { question: 'Why is Jeremy Bentham important?', answer: 'Jeremy Bentham founded utilitarianism, launching a tradition that now pervades ethics, law, and public policy. His principle provided a single, clear standard for evaluating laws and institutions that could challenge centuries of tradition and privilege. Utilitarian reasoning now underlies cost-benefit analysis, welfare economics, public health policy, and the effective altruism movement.' },
    { question: "What are Jeremy Bentham's major works?", answer: "Jeremy Bentham's major works include An Introduction to the Principles of Morals and Legislation, which systematically presents the greatest happiness principle and the felicific calculus. He also wrote A Fragment on Government, The Rationale of Reward, and his design for the Panopticon, a model prison based on constant potential observation." },
    { question: "What is Bentham's greatest happiness principle?", answer: "Bentham's greatest happiness principle holds that the right action is the one that produces the greatest total sum of happiness, measured as pleasure minus pain, for all those affected. Bentham developed a felicific calculus to quantify pleasures by their intensity, duration, certainty, proximity, fecundity, purity, and extent. Every person's happiness counts equally in this calculation." },
  ],
  'thomas-reid': [
    { question: 'Who was Thomas Reid?', answer: 'Thomas Reid (1710-1796) was a Scottish philosopher who founded the Scottish Common Sense school in direct response to David Hume\'s skepticism. He served as a professor at the University of Aberdeen and later at the University of Glasgow, and his ideas profoundly influenced the American founders through John Witherspoon at Princeton.' },
    { question: 'What did Thomas Reid believe?', answer: 'Thomas Reid believed that certain fundamental beliefs, such as the existence of the external world, the reliability of our senses, and basic moral truths, are warranted by common sense and do not need philosophical proof. He argued that in perception we are directly aware of external objects, not of mental intermediaries, and that human beings possess genuine free will through agent causation.' },
    { question: 'Why is Thomas Reid important?', answer: 'Thomas Reid was a major influence on American founding philosophy through John Witherspoon at Princeton, who taught Madison and trained a generation of American leaders. His direct realism in perception has been revived in contemporary analytic philosophy, and his challenge to representationalism anticipated twentieth-century critiques by Austin, Gibson, and McDowell.' },
    { question: "What are Thomas Reid's major works?", answer: "Thomas Reid's major works include An Inquiry into the Human Mind on the Principles of Common Sense, which rejects representationalism and defends direct realism. His Essays on the Intellectual Powers of Man addresses perception, memory, and reasoning, while Essays on the Active Powers of Man treats free will and moral agency." },
    { question: "What is Reid's common sense philosophy?", answer: "Reid's common sense philosophy holds that certain first principles, such as the existence of the external world and the reliability of memory, are self-evident to any competent adult and need no philosophical proof. Any attempt to prove them is self-defeating, since the proof must rely on principles less certain than the beliefs themselves. Reid argued that Hume's skepticism was a reductio ad absurdum of the representationalist theory of perception, not a genuine philosophical position." },
  ],
  'thomas-paine': [
    { question: 'Who was Thomas Paine?', answer: 'Thomas Paine (1737-1809) was an English-born political pamphleteer who became the eighteenth century\'s most widely read advocate for revolution and democracy. He arrived in the American colonies in 1774 carrying a letter from Benjamin Franklin, and within fourteen months published Common Sense, which persuaded the colonies to declare independence.' },
    { question: 'What did Thomas Paine believe?', answer: 'Thomas Paine believed that government is a necessary evil, that the rights of man are universal, self-evident, and non-negotiable, and that each generation has the right to govern itself without being bound by the dead. He argued that hereditary monarchy is absurd and that legitimate political authority comes only from the rational consent of the living.' },
    { question: 'Why is Thomas Paine important?', answer: 'Thomas Paine\'s pamphlets fueled both the American and French Revolutions and translated liberal philosophy into language that could move a continent. Common Sense sold proportionally more copies than almost any American publication in history and transformed the colonial debate from reconciliation with Britain to independence.' },
    { question: "What are Thomas Paine's major works?", answer: "Thomas Paine's major works include Common Sense, which made the philosophical case for American independence in plain language. Rights of Man defended the French Revolution against Edmund Burke, The Age of Reason applied Enlightenment rationalism to religion, and Agrarian Justice proposed an early version of universal basic income." },
    { question: "What was Paine's argument in Common Sense?", answer: "In Common Sense, Paine argued that hereditary monarchy is absurd, since royal legitimacy amounts to nothing more than descent from a successful conqueror. He contended that government is at best a necessary evil, that the British constitution was a confused mixture producing paralysis rather than liberty, and that America should declare independence and establish a democratic republic to demonstrate that the people can govern themselves." },
  ],
  'denis-diderot': [
    { question: 'Who was Denis Diderot?', answer: 'Denis Diderot (1713-1784) was a French philosopher, writer, and art critic who was the driving force behind the Encyclopedie, a 28-volume compendium of Enlightenment knowledge. Beyond this massive editorial project spanning over twenty years, he was an original philosopher who explored materialism, determinism, and consciousness in daring dialogues and essays.' },
    { question: 'What did Denis Diderot believe?', answer: 'Denis Diderot believed that making all human knowledge accessible through systematic compilation could change how people think. He argued that matter itself possesses a rudimentary form of sensitivity from which consciousness gradually emerges through increasing organizational complexity, and that honest philosophy must embrace contradiction rather than force reality into tidy systems.' },
    { question: 'Why is Denis Diderot important?', answer: 'Denis Diderot\'s Encyclopedie shaped the intellectual foundations of the French Revolution and established the principle that all human knowledge should be accessible to all people. His materialist philosophy of mind anticipated evolutionary thinking, emergentism, and modern neuroscience by nearly a century, and Hegel used his Rameau\'s Nephew as a central text in the Phenomenology of Spirit.' },
    { question: "What are Denis Diderot's major works?", answer: "Denis Diderot's major works include the Encyclopedie, the defining intellectual project of the Enlightenment that he edited for over twenty years. His philosophical dialogues include D'Alembert's Dream on materialist philosophy of mind, Rameau's Nephew exploring moral contradiction, and Jacques the Fatalist on determinism and narrative." },
    { question: "What was Diderot's Encyclopedie?", answer: "Diderot's Encyclopedie was a 28-volume compendium intended to contain all human knowledge, organized according to rational principles. It was subversive by design: by treating theology as one subject among many, giving detailed attention to crafts and trades, and using cross-references to undermine orthodoxy, it challenged the authority of church and crown. The project faced censorship and suppression but ultimately trained a generation to think critically." },
  ],
  'mary-wollstonecraft': [
    { question: 'Who was Mary Wollstonecraft?', answer: 'Mary Wollstonecraft (1759-1797) was a British writer and philosopher who wrote the first great work of feminist philosophy. She entered the political debate of her era by replying to Edmund Burke\'s defense of the old order, then extended her critique of unjust hierarchy to argue for women\'s equal education, legal rights, and political participation.' },
    { question: 'What did Mary Wollstonecraft believe?', answer: 'Mary Wollstonecraft believed that women are not naturally inferior to men but appear so only because they are denied education and opportunity. She argued that if reason is what distinguishes human beings, and women possess reason equally with men, then denying women education is both unjust and irrational. True virtue requires independence, which is impossible without education and economic self-sufficiency.' },
    { question: 'Why is Mary Wollstonecraft important?', answer: 'Mary Wollstonecraft wrote the founding text of modern feminist philosophy. She applied Enlightenment principles of reason and equality to half the human race, and her argument that women\'s apparent deficiencies are socially constructed rather than natural anticipated the central insight of later feminism by nearly two centuries and directly influenced the suffrage movement and Simone de Beauvoir.' },
    { question: "What are Mary Wollstonecraft's major works?", answer: "Mary Wollstonecraft's major works include A Vindication of the Rights of Woman, the founding text of feminist philosophy arguing for women's equal education. She also wrote A Vindication of the Rights of Men, one of the first replies to Edmund Burke's defense of the old order, and Thoughts on the Education of Daughters." },
    { question: "What is Wollstonecraft's argument for women's education?", answer: "Wollstonecraft argued that if reason is the faculty that distinguishes humans from animals, and women possess reason equally with men, then denying women education is irrational. Women appear intellectually inferior not because nature made them so but because society has systematically denied them the opportunity to develop their rational capacities. Give women the same education as men, she contended, and the supposed natural differences will largely disappear." },
  ],
  'thomas-jefferson': [
    { question: 'Who was Thomas Jefferson?', answer: 'Thomas Jefferson (1743-1826) was an American statesman, philosopher, and the principal author of the Declaration of Independence. He was the most philosophically engaged of the American founders, synthesizing Locke\'s natural rights theory, the Scottish Enlightenment\'s moral sense philosophy, and classical republicanism into a new framework for political legitimacy.' },
    { question: 'What did Thomas Jefferson believe?', answer: 'Thomas Jefferson believed that human beings are endowed with unalienable rights to life, liberty, and the pursuit of happiness, that these rights are pre-political and cannot be legitimately taken away, and that government exists solely to protect them. He argued that republican government requires an educated citizenry and that independent small farmers are the natural constituency of democratic self-governance.' },
    { question: 'Why is Thomas Jefferson important?', answer: 'Thomas Jefferson authored the founding philosophical document of American constitutional democracy. The Declaration of Independence\'s natural rights framework has been invoked by every American liberation movement from abolition to civil rights, and its philosophical argument became the template for democratic movements worldwide.' },
    { question: "What are Thomas Jefferson's major works?", answer: "Thomas Jefferson's major works include the Declaration of Independence, which synthesizes natural rights philosophy into a revolutionary manifesto. He also wrote Notes on the State of Virginia, authored the Virginia Statute for Religious Freedom, and maintained an extensive philosophical correspondence, especially with John Adams and James Madison." },
    { question: "What is Jefferson's natural rights philosophy?", answer: "Jefferson's natural rights philosophy holds that human beings are endowed by their Creator with unalienable rights to life, liberty, and the pursuit of happiness. These rights exist before government and cannot be legitimately taken away. Government derives its just powers from the consent of the governed, and when it becomes destructive of these ends, the people have the right to alter or abolish it." },
  ],
  'james-madison': [
    { question: 'Who was James Madison?', answer: 'James Madison (1751-1836) was the principal architect of the U.S. Constitution and the most philosophically rigorous of the American founders. Drawing on Montesquieu, Hume, and his deep study of ancient and modern republics, he designed a system of government that channels human self-interest rather than relying on human virtue.' },
    { question: 'What did James Madison believe?', answer: 'James Madison believed that factions are inevitable in a free society and that the best remedy is a large republic where competing factions neutralize each other. He argued that the preservation of liberty cannot depend on the virtue of rulers, and that the structure of government itself must prevent the concentration of power through checks and balances.' },
    { question: 'Why is James Madison important?', answer: 'James Madison designed the world\'s most enduring written constitution. The Federalist Papers, which he co-authored with Hamilton and Jay, remain required reading in political philosophy, and his insight that institutional design must harness self-interest rather than rely on virtue has been adopted by constitutional democracies around the world.' },
    { question: "What are James Madison's major works?", answer: "James Madison's major works include The Federalist Papers, especially Nos. 10 and 51, which provide the philosophical blueprint of the American constitutional system. His Memorial and Remonstrance Against Religious Assessments is a foundational argument for religious liberty, and his Notes of Debates in the Federal Convention document the creation of the Constitution." },
    { question: "What is Madison's theory of faction in Federalist No. 10?", answer: "In Federalist No. 10, Madison argued that factions, groups pursuing interests adverse to the rights of others, are inevitable because human beings have different opinions, abilities, and amounts of property. You cannot eliminate faction without eliminating liberty itself. His solution was the extended republic: in a large nation with many competing factions, no single faction can dominate, and the diversity that makes consensus difficult makes oppression nearly impossible." },
  ],
  'alexander-hamilton': [
    { question: 'Who was Alexander Hamilton?', answer: 'Alexander Hamilton (1755-1804) was the most intellectually aggressive of the American founders. A self-made immigrant who rose from poverty in the Caribbean, he co-authored the Federalist Papers, designed the American financial system as the first Secretary of the Treasury, and argued for a strong national government capable of protecting liberty and promoting commerce.' },
    { question: 'What did Alexander Hamilton believe?', answer: 'Alexander Hamilton believed that liberty requires not just limited government but effective government, a state strong enough to enforce laws, maintain public credit, and defend commerce. He argued that anarchy and tyranny are partners rather than opposites, and that where government is too weak to maintain order, private power fills the vacuum and dominates the vulnerable.' },
    { question: 'Why is Alexander Hamilton important?', answer: 'Alexander Hamilton created the intellectual framework for American capitalism and for the strong but constitutionally limited federal government. His financial system made the United States economically viable, his Federalist No. 78 provided the philosophical foundation for judicial review, and his debate with Jefferson over the proper scope of government continues to define American politics.' },
    { question: "What are Alexander Hamilton's major works?", answer: "Alexander Hamilton's major works include The Federalist Papers, especially Nos. 1, 6, 9, 70, and 78, defending the Constitution and articulating the case for energetic government. His Report on Manufactures argued for industrial policy, and his Report on Public Credit established the principles of American public finance." },
    { question: "What is Hamilton's argument for energetic government?", answer: "Hamilton argued that liberty and energetic government are allies, not adversaries. A government too feeble to act is no protection for anyone's liberty, as the weak Articles of Confederation had demonstrated. He contended that commercial prosperity and individual liberty reinforce each other, and that a properly structured national government, energetic within its constitutional limits, serves freedom rather than threatening it." },
  ],
  'benjamin-franklin': [
    { question: 'Who was Benjamin Franklin?', answer: 'Benjamin Franklin (1706-1790) was an American polymath who embodied the Enlightenment ideal: a printer, scientist, diplomat, inventor, and moral philosopher. He made fundamental contributions to the understanding of electricity, invented the lightning rod and bifocal spectacles, founded major public institutions, and served as a key diplomat securing French support for American independence.' },
    { question: 'What did Benjamin Franklin believe?', answer: 'Benjamin Franklin believed that ordinary people, using reason and effort, can improve both themselves and their world. He held that character is not fixed by birth but can be cultivated through sustained rational effort, and that civic virtue expressed through voluntary association is more creative and adaptive than either government direction or individual effort alone.' },
    { question: 'Why is Benjamin Franklin important?', answer: 'Benjamin Franklin embodied the Enlightenment ideal that reason, virtue, and effort can improve both individual character and society. He democratized the philosophical project of self-improvement, anticipated pragmatist philosophy, and his institution-building established the model of voluntary civic association that Tocqueville would later identify as the genius of American democracy.' },
    { question: "What are Benjamin Franklin's major works?", answer: "Benjamin Franklin's major works include The Autobiography of Benjamin Franklin, a philosophical document presenting his systematic experiment in moral self-cultivation. Poor Richard's Almanack offered practical wisdom and moral guidance to a popular audience, and his extensive Letters and Essays addressed scientific, political, and philosophical questions." },
    { question: "What is Franklin's 13 virtues project?", answer: "Franklin's 13 virtues project was a systematic experiment in moral self-cultivation. He identified thirteen virtues, including temperance, silence, order, resolution, and humility, and designed a practical method for acquiring them: a weekly chart tracking his performance on each virtue, focusing on one per week in a thirteen-week cycle. The project demonstrated that character can be cultivated through method and effort, anticipating modern habit-formation research." },
  ],
  'edmund-burke': [
    { question: 'Who was Edmund Burke?', answer: 'Edmund Burke (1729-1797) was an Irish-born British statesman and philosopher who is considered the founder of modern conservatism. He supported the American Revolution but denounced the French Revolution, not because he opposed liberty, but because he believed the French were destroying the inherited institutions that make liberty possible.' },
    { question: 'What did Edmund Burke believe?', answer: 'Edmund Burke believed that human reason is too limited and fallible to redesign society from scratch, and that the accumulated wisdom embedded in traditions, customs, and institutions represents centuries of trial and error that no individual mind can replicate. He argued that society is a partnership between the living, the dead, and the unborn, and that radical attempts to rebuild society from abstract principles inevitably lead to tyranny.' },
    { question: 'Why is Edmund Burke important?', answer: 'Edmund Burke founded modern conservatism, and his prediction that the French Revolution would end in tyranny was vindicated before his critics could respond. His argument that inherited institutions encode social wisdom that cannot be replicated by rational reconstruction has shaped conservative thought from Tocqueville through Oakeshott, and his early work on the sublime directly influenced Kant\'s aesthetics and the Romantic movement.' },
    { question: "What are Edmund Burke's major works?", answer: "Edmund Burke's major works include Reflections on the Revolution in France, the founding text of modern conservatism arguing against radical social reconstruction. His early A Philosophical Enquiry into the Sublime and Beautiful was a landmark work in aesthetics, and his Speech to the Electors of Bristol articulated the theory of representative government." },
    { question: "What is Burke's intergenerational social contract?", answer: "Burke reconceived the social contract as a partnership not only between those who are living, but between the living, the dead, and the unborn. Each generation inherits a civilization it did not create, benefits from sacrifices it did not make, and has obligations to preserve and improve what it received for those who come after. To treat inherited institutions as mere obstacles to the will of the current majority is to betray both the dead who built them and the unborn who will need them." },
  ],

  'g-w-f-hegel': [
    { question: 'Who was G.W.F. Hegel?', answer: 'Georg Wilhelm Friedrich Hegel was a German philosopher born in Stuttgart in 1770 who became professor of philosophy at the University of Berlin, where he dominated German intellectual life until his death in 1831. He studied theology at the Tubingen seminary alongside the poet Holderlin and the philosopher Schelling, and produced his first masterwork, the Phenomenology of Spirit, in 1807. His philosophical system is among the most ambitious ever attempted, seeking to show that all of reality is the self-development of a single rational process he called Absolute Spirit.' },
    { question: 'What did G.W.F. Hegel believe?', answer: 'G.W.F. Hegel believed that reality is the self-development of Absolute Spirit through dialectical progression, where every concept or historical condition generates its opposite, and their conflict drives toward a higher unity. He argued that history has a rational direction driven by the internal logic of its own contradictions, and that philosophy\'s task is to comprehend this rationality rather than impose ideals from outside. He held that the rational is real and the real is rational, meaning reality has an inherent rational structure that philosophy can uncover.' },
    { question: 'Why is G.W.F. Hegel important?', answer: 'G.W.F. Hegel shaped the development of virtually every major philosophical movement that followed him, including Marxism, existentialism, pragmatism, and critical theory. Karl Marx adapted Hegel\'s dialectic to material economic conditions, while Kierkegaard defined his existentialism in opposition to Hegel\'s system. His influence extends across political philosophy, aesthetics, philosophy of history, and logic, making him one of the most consequential thinkers in the Western tradition.' },
    { question: "What are G.W.F. Hegel's major works?", answer: "G.W.F. Hegel's major works include the Phenomenology of Spirit (1807), which traces the development of consciousness from simple sense-certainty to absolute knowledge, and the Science of Logic, which lays out his dialectical method in detail. His Philosophy of Right addresses political philosophy and the state, while his Lectures on the Philosophy of History and Lectures on Aesthetics apply his system to historical development and art respectively." },
    { question: "What is Hegel's dialectic?", answer: "Hegel's dialectic is the process by which thought, history, and reality develop through contradiction and resolution. Every concept or historical condition (the thesis) contains internal tensions that generate its opposite (the antithesis), and their conflict produces a higher unity (the synthesis) that preserves what was true in both while transcending their limitations. This pattern repeats at every level, from the development of philosophical concepts to the progress of political institutions, and Hegel saw it as the fundamental engine driving all of reality forward." },
  ],
  'arthur-schopenhauer': [
    { question: 'Who was Arthur Schopenhauer?', answer: 'Arthur Schopenhauer was a German philosopher born in 1788 who became known as the great pessimist of Western philosophy. Drawing on both Kant and Indian philosophy, he developed a metaphysical system centered on the concept of a blind, purposeless Will driving all of reality. He spent much of his career in obscurity, with his work gaining wider recognition only later in his life before his death in 1860.' },
    { question: 'What did Arthur Schopenhauer believe?', answer: 'Arthur Schopenhauer believed that the world is driven by a blind, purposeless, and insatiable Will that manifests as endless striving and suffering. He argued that individual consciousness is the Will becoming aware of itself, which inevitably produces pain, and that life oscillates between the suffering of unfulfilled desire and the emptiness of boredom. He held that relief from this condition comes through aesthetic contemplation, music, compassion, and ultimately the denial of the will-to-live.' },
    { question: 'Why is Arthur Schopenhauer important?', answer: 'Arthur Schopenhauer was the first major Western philosopher to engage seriously with Eastern philosophy, particularly Hindu and Buddhist thought, opening a channel between Eastern and Western traditions. His concept of the Will as a pre-rational driving force anticipated key ideas in Nietzsche, Freud\'s theory of the unconscious, and modern psychology. He also profoundly influenced artists and writers including Wagner, Tolstoy, Thomas Mann, and Beckett.' },
    { question: "What are Arthur Schopenhauer's major works?", answer: "Arthur Schopenhauer's central work is The World as Will and Representation, first published in 1818 and substantially expanded in 1844, which lays out his entire philosophical system. On the Freedom of the Will addresses moral responsibility and determinism. His Parerga and Paralipomena, a collection of essays and aphorisms published in 1851, became his most widely read work during his lifetime and helped bring him belated recognition." },
    { question: "What is Schopenhauer's concept of the Will?", answer: "Schopenhauer's concept of the Will holds that behind the world of appearances lies a blind, purposeless, and insatiable force that drives all of nature, from the force of gravity to human desire. He argued that we have direct access to this reality through our own bodies, since when we move our arm we experience it from within as an act of willing, and this inner experience gives us the key to the entire cosmos. Individual organisms are not independent beings but temporary expressions of this single cosmic force, and at the human level, the Will becomes conscious of its own insatiability, which is the fundamental source of suffering." },
  ],
  'soren-kierkegaard': [
    { question: 'Who was Soren Kierkegaard?', answer: 'Soren Kierkegaard was a Danish philosopher born in Copenhagen in 1813 who is widely regarded as the originator of the existentialist tradition. Writing under numerous pseudonyms, he produced a body of work that attacked Hegel\'s philosophical system for ignoring the anguish and passion of individual existence. He died in 1855 at the age of forty-two, and his ideas went on to profoundly influence twentieth-century philosophy and theology.' },
    { question: 'What did Soren Kierkegaard believe?', answer: 'Soren Kierkegaard believed that truth is subjective and that authentic existence demands passionate commitment in the face of uncertainty. He insisted that the most important truths about how to live, what to believe, and who to become cannot be captured in abstract systems but must be personally lived and chosen. He argued that human life moves through three stages of existence, the aesthetic, the ethical, and the religious, and that the transition between them requires not argument but a fundamental leap of the whole person.' },
    { question: 'Why is Soren Kierkegaard important?', answer: 'Soren Kierkegaard originated the existentialist tradition that shaped twentieth-century philosophy through thinkers like Heidegger, Sartre, Camus, and de Beauvoir. His analysis of anxiety, authenticity, and the flight into conformity directly provided the groundwork for Heidegger\'s concept of das Man and Sartre\'s bad faith. He also profoundly influenced modern theology through thinkers like Karl Barth and Paul Tillich, who drew on his concept of the leap of faith.' },
    { question: "What are Soren Kierkegaard's major works?", answer: "Soren Kierkegaard's major works include Either/Or (1843), which dramatizes the contrast between the aesthetic and ethical stages of existence, and Fear and Trembling (1843), which examines Abraham's sacrifice of Isaac as a paradigm of the leap of faith. The Concept of Anxiety (1844) analyzes anxiety as the consequence of human freedom, while The Sickness Unto Death (1849) explores despair as a failure of selfhood. His Concluding Unscientific Postscript (1846) is his most sustained philosophical argument for subjective truth against Hegelian rationalism." },
    { question: "What is Kierkegaard's leap of faith?", answer: "Kierkegaard's leap of faith is the idea that rational argument cannot bridge the gap to religious faith, and that one must make a passionate, personal commitment beyond what reason can justify. He illustrated this through the story of Abraham, who obeyed God's command to sacrifice Isaac despite it being ethically monstrous and rationally absurd, trusting in something that could not be proven. The concept challenged the Enlightenment's confidence in pure reason and became foundational to existentialism's insistence that the most important human decisions fall beyond what evidence and logic can settle." },
  ],
  'karl-marx': [
    { question: 'Who was Karl Marx?', answer: 'Karl Marx was a German philosopher, economist, and revolutionary born in Trier, Prussia in 1818, who studied law and philosophy at the universities of Bonn and Berlin before turning to journalism. Expelled from Germany, France, and Belgium for his revolutionary activities, he settled permanently in London in 1849, where he spent decades researching and writing in the British Museum while often living in desperate poverty. His masterwork, Das Kapital, provided a detailed analysis of the internal logic of capitalism, and his ideas reshaped how we think about the relationship between economic structures, political institutions, and the world of ideas.' },
    { question: 'What did Karl Marx believe?', answer: 'Karl Marx believed that history is driven by class struggle between those who own the means of production and those who labor, and that the economic base of society shapes its political, legal, religious, and intellectual superstructure. He argued that capitalism alienates workers from their labor, their products, their fellow human beings, and their own creative human nature. He held that capitalism contains internal contradictions between social production and private ownership that would eventually produce revolutionary transformation to a new economic system.' },
    { question: 'Why is Karl Marx important?', answer: 'Karl Marx reshaped political theory, economics, sociology, and historiography by insisting that economic structures shape political and cultural life. His concept of historical materialism provided an analytical framework that influenced thinkers across the social sciences, from Max Weber to the Annales school of French historiography. His analysis of alienation influenced existentialism, critical theory, and modern psychology, while his political writings shaped revolutionary movements worldwide throughout the twentieth century.' },
    { question: "What are Karl Marx's major works?", answer: "Karl Marx's most important work is Das Kapital, a multi-volume analysis of the internal logic and contradictions of capitalism. The Communist Manifesto (1848), co-written with Friedrich Engels, is his most widely read political text, laying out the theory of class struggle and calling for proletarian revolution. His Economic and Philosophic Manuscripts of 1844 introduced the concept of alienation, while The German Ideology (co-written with Engels) developed the theory of historical materialism and ideology." },
    { question: "What is Marx's theory of class struggle?", answer: "Marx's theory of class struggle holds that every society is divided between those who own the means of production and those who must sell their labor, and that the conflict between these classes is the fundamental driver of historical change. Each mode of production, from slavery through feudalism to capitalism, generates contradictions between the interests of owners and workers that eventually produce revolutionary transformation to a new economic system. Marx argued that under capitalism, the bourgeoisie who own capital and the proletariat who labor are locked in an inherent conflict over the surplus value created by workers but appropriated by owners." },
  ],
  'john-stuart-mill': [
    { question: 'Who was John Stuart Mill?', answer: 'John Stuart Mill was a British philosopher and political economist born in 1806 who received an extraordinary education from his father, learning Greek at age three, Latin at eight, and logic at twelve. He suffered a devastating mental breakdown at twenty, from which he recovered through the discovery of poetry and emotional life, an experience that permanently shaped his philosophy. He spent most of his career at the East India Company while producing influential works on ethics, political philosophy, and logic, and he served in Parliament where he championed women\'s suffrage.' },
    { question: 'What did John Stuart Mill believe?', answer: 'John Stuart Mill believed that actions are right insofar as they produce the greatest happiness for the greatest number, refining Bentham\'s utilitarianism by arguing that pleasures differ in quality, not just quantity. He held that the only legitimate reason for society to restrict individual freedom is to prevent harm to others, a principle now known as the harm principle. He also defended free expression as essential to the pursuit of truth and argued for gender equality as a matter of philosophical principle.' },
    { question: 'Why is John Stuart Mill important?', answer: 'John Stuart Mill refined utilitarianism from a crude calculus of pleasure into a sophisticated moral theory that remains central to ethical philosophy. His On Liberty established the foundational framework for modern liberal democracy and civil liberties, with the harm principle informing debates about free speech, drug policy, and the limits of government power. He was also one of the first prominent philosophers to argue systematically for gender equality in The Subjection of Women.' },
    { question: "What are John Stuart Mill's major works?", answer: "John Stuart Mill's On Liberty (1859) is a landmark defense of individual freedom and free expression that remains a standard reference in political philosophy. His Utilitarianism (1863) refined and humanized Bentham's moral theory by introducing the distinction between higher and lower pleasures. A System of Logic (1843) was a major contribution to the philosophy of science and inductive reasoning, while The Subjection of Women (1869) was one of the first systematic philosophical arguments for gender equality." },
    { question: "What is Mill's harm principle?", answer: "Mill's harm principle states that the only legitimate reason for society or government to restrict an individual's freedom against their will is to prevent harm to others. Over their own body and mind, the individual is sovereign, and mere offense, moral disapproval, or the belief that someone is harming themselves does not justify coercion. Mill argued that this principle serves society as a whole because permitting experiments in living and free expression drives intellectual and moral progress, while enforced conformity leads to stagnation." },
  ],
  'friedrich-nietzsche': [
    { question: 'Who was Friedrich Nietzsche?', answer: 'Friedrich Nietzsche was a German philosopher born in 1844 who was appointed professor of classical philology at the University of Basel at the age of twenty-four, the youngest person ever to hold that chair. Chronic ill health forced him to resign, and he spent a decade as a nomadic writer producing a rapid outpouring of books that received almost no attention during his sane life. In January 1889 he collapsed in Turin and spent the last eleven years of his life in mental incapacity, while his sister distorted and manipulated his unpublished writings.' },
    { question: 'What did Friedrich Nietzsche believe?', answer: 'Friedrich Nietzsche believed that the foundations of Western morality, meaning, and truth built on a Christian-Platonic framework had collapsed, a crisis he captured in the proclamation that God is dead. He argued that morality is not a set of eternal truths but a historical product shaped by power dynamics, distinguishing between master morality created by the strong and slave morality arising from the resentment of the weak. He challenged humanity to create new values and embrace life fully, proposing the ideal of the Ubermensch and the test of eternal recurrence as measures of life-affirmation.' },
    { question: 'Why is Friedrich Nietzsche important?', answer: 'Friedrich Nietzsche influenced virtually every major intellectual movement of the twentieth century, including existentialism, postmodernism, psychology, and literary criticism. His genealogical method of asking where moral values come from and whose interests they serve shaped Foucault, critical theory, and the entire tradition of questioning the origins and functions of moral beliefs. His psychological insights anticipated key ideas in Freud and Jung, and his explosive aphoristic style made him one of the most widely read philosophers in popular culture.' },
    { question: "What are Friedrich Nietzsche's major works?", answer: "Friedrich Nietzsche's major works include Thus Spoke Zarathustra, a philosophical novel introducing the concepts of the Ubermensch and eternal recurrence, and Beyond Good and Evil, which challenges conventional morality. On the Genealogy of Morality traces the historical origins of moral concepts through the distinction between master and slave morality. The Gay Science contains the famous proclamation of the death of God, while Ecce Homo is his provocative autobiography and Twilight of the Idols offers a concise summary of his mature philosophy." },
    { question: "What did Nietzsche mean by 'God is dead'?", answer: "Nietzsche's proclamation that God is dead is not a theological argument for atheism but a cultural diagnosis. He argued that the Enlightenment's own commitment to honesty and rational inquiry had gradually undermined the Christian-Platonic framework that had grounded Western morality, meaning, and truth for centuries. The terrifying question he raised was what happens next: if God was the foundation of morality and meaning, then His death threatens to plunge civilization into nihilism, the conviction that nothing matters. Nietzsche considered this the greatest danger facing modern civilization and challenged humanity to create new values adequate to a godless world." },
  ],
  'william-james': [
    { question: 'Who was William James?', answer: 'William James was an American philosopher and psychologist born in 1842 who became the great popularizer of American pragmatism and a pioneer of modern psychology. He spent his career at Harvard, where he established one of the first psychology laboratories in the United States and produced influential works across philosophy, psychology, and the study of religion. He died in 1910, having shaped American intellectual life through both his writings and his engaging public lectures.' },
    { question: 'What did William James believe?', answer: 'William James believed that truth is not a static correspondence with reality but a living relationship between ideas and experience, holding that an idea is true insofar as it proves useful in practice and leads to successful predictions and actions. He argued that experience is a continuous, flowing stream rather than a sequence of discrete sensations, coining the term stream of consciousness. He also defended the right to believe in matters where evidence is insufficient but the choice is genuine and consequential, such as religious faith and moral commitment.' },
    { question: 'Why is William James important?', answer: 'William James popularized American pragmatism, which became one of America\'s most original contributions to world philosophy, influencing thinkers from John Dewey to Richard Rorty. His Principles of Psychology pioneered the scientific study of consciousness and introduced the concept of the stream of consciousness, which directly inspired the literary technique of the same name in Joyce, Woolf, and Faulkner. His work on radical empiricism and the pragmatic theory of truth anticipated developments in twentieth-century philosophy of science and epistemology.' },
    { question: "What are William James's major works?", answer: "William James's Pragmatism (1907) laid out his theory that truth is what works in practice, becoming the defining text of the pragmatist movement. The Principles of Psychology (1890) was a groundbreaking two-volume work that introduced the concept of the stream of consciousness and helped establish psychology as a scientific discipline. The Varieties of Religious Experience (1902) examined religious and mystical states with empirical rigor, while The Will to Believe (1896) defended the right to faith when evidence is insufficient." },
    { question: "What is James's pragmatic theory of truth?", answer: "William James's pragmatic theory of truth holds that an idea becomes true insofar as it helps us navigate experience, make successful predictions, and integrate new information with what we already believe. Rather than truth being a static correspondence between a proposition and a fact, James argued that truth happens to an idea through the ongoing process of human beings grappling with a resistant world. He insisted that truth is constrained by experience, since a belief that consistently leads to failed predictions will not survive, but maintained that abstract correspondence theories that cannot specify how truth makes a practical difference are empty formalisms." },
  ],
  'ralph-waldo-emerson': [
    { question: 'Who was Ralph Waldo Emerson?', answer: 'Ralph Waldo Emerson was an American essayist, lecturer, and philosopher born in 1803 who became the leading voice of American Transcendentalism. After resigning from the Unitarian ministry, he launched a career as a public intellectual, delivering lectures and publishing essays that championed self-reliance, individualism, and the spiritual dimension of nature. His influence on American culture was enormous, inspiring generations of writers, activists, and thinkers from Thoreau and Whitman to Nietzsche and the counterculture movement.' },
    { question: 'What did Ralph Waldo Emerson believe?', answer: 'Ralph Waldo Emerson believed that every person has direct access to universal truth through intuition and that trusting one\'s own instincts and convictions is more important than deferring to external authority. He held that all individual souls are part of one universal spirit, which he called the Over-Soul, and that the boundaries between self and world are ultimately illusory. He also believed that nature is not raw material to be exploited but a living text to be read, where every natural fact is a symbol of a spiritual fact.' },
    { question: 'Why is Ralph Waldo Emerson important?', answer: 'Ralph Waldo Emerson was the central figure of American Transcendentalism and defined the American ideal of individualism that has shaped the nation\'s culture ever since. He directly influenced Thoreau, Whitman, and the entire tradition of American literary and philosophical individualism. His ideas also reached across the Atlantic, influencing Nietzsche\'s celebration of the sovereign individual, and his democratic insistence that wisdom is available to everyone through direct experience remains a distinctively American contribution to world philosophy.' },
    { question: "What are Ralph Waldo Emerson's major works?", answer: "Ralph Waldo Emerson's essay Self-Reliance (1841) is his most famous work, arguing that trusting one's own convictions is the foundation of genius and authentic living. His essay Nature (1836) is the founding document of American Transcendentalism, presenting the natural world as a living expression of spiritual reality. The American Scholar (1837) called for intellectual independence from European tradition, while The Over-Soul (1841) laid out his metaphysical vision of a universal spirit connecting all living beings." },
    { question: "What is Emerson's concept of self-reliance?", answer: "Emerson's concept of self-reliance holds that every person should trust their own instincts and convictions above all external authority, including churches, governments, inherited traditions, and even books. He grounded this in a metaphysical claim that each person has direct access to universal truth through intuition, so the individual who trusts their own perception is drawing from the same source that all great thinkers have drawn from. Self-reliance is not mere nonconformity but the intellectual courage to revise one's views, abandon positions that no longer hold, and stand alone against the crowd when necessary." },
  ],
  'henry-david-thoreau': [
    { question: 'Who was Henry David Thoreau?', answer: 'Henry David Thoreau was an American philosopher, essayist, and naturalist born in Concord, Massachusetts in 1817 who was a protege of Ralph Waldo Emerson. He is best known for his two-year experiment in simple living at Walden Pond and for his essay on civil disobedience, written after he refused to pay a tax supporting the Mexican-American War and slavery. He died of tuberculosis in 1862 at the age of forty-four, leaving behind a body of work that would profoundly influence movements for social justice and environmental conservation.' },
    { question: 'What did Henry David Thoreau believe?', answer: 'Henry David Thoreau believed that the individual conscience is a higher authority than any unjust law and that citizens have a moral obligation to refuse compliance with government injustice. He held that most people live lives of quiet desperation, enslaved by unnecessary work, possessions, and social convention, and that simplifying life to its genuine necessities liberates time for what actually matters: thought, observation, friendship, and contact with nature. He also believed that nature is not simply scenery or a resource but a source of moral and philosophical knowledge that civilization cannot afford to lose.' },
    { question: 'Why is Henry David Thoreau important?', answer: 'Henry David Thoreau\'s essay on civil disobedience became one of the most influential political texts in modern history, directly inspiring Gandhi\'s philosophy of nonviolent resistance and Martin Luther King Jr.\'s strategy during the American civil rights movement. His Walden is the founding text of American environmental philosophy, launching a tradition of nature writing that runs from John Muir through Aldo Leopold to modern environmentalism. He demonstrated that philosophy need not be abstract argument but can be a way of living, tested by practice.' },
    { question: "What are Henry David Thoreau's major works?", answer: "Henry David Thoreau's Walden (1854) is a masterpiece of philosophical reflection drawn from his two-year experiment in simple living at Walden Pond, exploring what is truly necessary for a good human life. His essay Civil Disobedience (1849), originally titled Resistance to Civil Government, articulated the principle that individuals have a moral duty to resist unjust government, becoming a foundational text for nonviolent resistance movements worldwide. A Week on the Concord and Merrimack Rivers (1849) was his first book, blending travel narrative with philosophical meditation." },
    { question: "What is Thoreau's philosophy of civil disobedience?", answer: "Thoreau's philosophy of civil disobedience holds that when a government enacts unjust laws, citizens are not simply permitted but morally obligated to refuse compliance, even at personal cost. He argued that merely voting against injustice is insufficient because it only expresses a preference without stopping the injustice from continuing, and that the only action matching the urgency of injustice is direct personal refusal. The state derives its authority from the consent of the governed, and when it acts unjustly, that consent can and should be withdrawn through noncooperation, tax refusal, and acceptance of the consequences." },
  ],
  'alexis-de-tocqueville': [
    { question: 'Who was Alexis de Tocqueville?', answer: 'Alexis de Tocqueville was a French political philosopher and aristocrat born in 1805 who traveled to America in 1831, ostensibly to study the penitentiary system, and produced one of the most penetrating analyses of democratic society ever written. His family had been devastated by the French Revolution, with his great-grandfather guillotined for defending Louis XVI, an experience that shaped his lifelong concern with the dangers and possibilities of democracy. He died in 1859, leaving behind works that continue to define debates about democratic governance.' },
    { question: 'What did Alexis de Tocqueville believe?', answer: 'Alexis de Tocqueville believed that democracy\'s greatest threat is not tyranny from above but the soft despotism of conformity, where the majority wields immense social and psychological power that quietly discourages independent thought. He argued that democratic societies risk producing a new kind of unfreedom: a mild, paternalistic administrative power that oversees every aspect of citizens\' lives while sparing them the trouble of thinking and choosing for themselves. He also believed that voluntary associations are the genius of American democracy, creating intermediate institutions that protect citizens from both isolation and state dependency.' },
    { question: 'Why is Alexis de Tocqueville important?', answer: 'Alexis de Tocqueville identified forms of democratic unfreedom that earlier political philosophy had overlooked, particularly the tyranny that operates through social pressure rather than political coercion. His analysis directly influenced John Stuart Mill\'s On Liberty and shaped subsequent theories of democratic participation from Robert Putnam\'s work on social capital to contemporary debates about civic engagement. His prophecy of soft despotism, describing how democratic citizens would incrementally surrender self-governance in exchange for administrative comfort, has proved strikingly accurate as a description of modern Western governance.' },
    { question: "What are Alexis de Tocqueville's major works?", answer: "Alexis de Tocqueville's Democracy in America, published in two volumes in 1835 and 1840, is his masterwork and one of the most important books ever written about democratic society, examining how equality shapes manners, thought, religion, and institutions. The first volume focuses on American political institutions, while the second analyzes the broader social and psychological effects of democratic equality. His later work, The Old Regime and the Revolution, examined the French Revolution and argued that many of its centralizing tendencies were continuations of the old monarchical order rather than breaks from it." },
    { question: "What is Tocqueville's concept of the tyranny of the majority?", answer: "Tocqueville's tyranny of the majority describes how in a democracy, the majority wields not just political power but immense social and psychological power that operates on the mind rather than the body. The democratic citizen who holds an unpopular opinion finds not that he is persecuted but that he is alone, as friends fall away and career prospects suffer. This tyranny does not break the will but softens and guides it, producing a society of comfortable conformists who think they are free because no one is actively coercing them, but who have quietly surrendered the independence of mind that genuine freedom requires." },
  ],
  'charles-sanders-peirce': [
    { question: 'Who was Charles Sanders Peirce?', answer: 'Charles Sanders Peirce was an American philosopher, logician, and scientist born in 1839 who is recognized as the founder of pragmatism, though William James later popularized and, Peirce felt, distorted the doctrine. He made original contributions to logic, semiotics, scientific methodology, and the philosophy of inquiry while spending years working for the United States Coast and Geodetic Survey. Brilliant but difficult, he spent much of his life in poverty, and his genius was recognized only posthumously after his death in 1914.' },
    { question: 'What did Charles Sanders Peirce believe?', answer: 'Charles Sanders Peirce believed that the meaning of any concept lies entirely in the practical consequences it implies, a principle he called the pragmatic maxim. He argued that if two concepts produce identical practical effects under all conceivable circumstances, they mean the same thing, and any supposed difference between them is merely verbal. He also held that the scientific method, as a self-correcting communal enterprise, is the only reliable way to fix belief, and that all thought occurs in signs, with no thinking possible without representation.' },
    { question: 'Why is Charles Sanders Peirce important?', answer: 'Charles Sanders Peirce founded the pragmatist tradition, which became America\'s most original contribution to world philosophy, with both William James and John Dewey acknowledging him as the originator. He also founded modern semiotics alongside Ferdinand de Saussure, developing a triadic sign theory that proved more flexible and powerful than Saussure\'s dyadic model and has been applied across linguistics, cognitive science, and AI research. His pragmatic maxim anticipated the logical positivists\' verification principle and continues to influence philosophy of language and philosophy of science.' },
    { question: "What are Charles Sanders Peirce's major works?", answer: "Charles Sanders Peirce's most influential essays include How to Make Our Ideas Clear (1878), which first articulated the pragmatic maxim, and The Fixation of Belief (1877), which analyzed four methods by which human beings settle their opinions and argued for the superiority of the scientific method. He never produced a single systematic book during his lifetime, and his vast body of writing was assembled posthumously in the eight-volume Collected Papers, which contain his contributions to logic, semiotics, metaphysics, and scientific methodology." },
    { question: "What is Peirce's pragmatic maxim?", answer: "Peirce's pragmatic maxim states that to understand what a concept means, you must consider what practical effects the object of that concept could conceivably produce, and that complete list of effects is the entire meaning of the concept. If two concepts produce identical practical effects under all conceivable circumstances, they mean the same thing and any supposed difference is merely verbal. Peirce developed this as a method for clarifying philosophical concepts and dissolving pseudo-problems, insisting it was a theory of meaning rather than a theory of truth, which is how he distinguished his position from William James's later, more liberal version of pragmatism." },
  ],
  'john-dewey': [
    { question: 'Who was John Dewey?', answer: 'John Dewey was an American philosopher, psychologist, and educational reformer born in 1859 who became one of the leading public intellectuals of the early twentieth century. He began his career as a Hegelian idealist before moving toward a naturalistic pragmatism, and his experience running the Laboratory School at the University of Chicago convinced him that learning through active inquiry is the fundamental structure of all rational thought. He lived until 1952, producing an enormous body of work that reshaped American education, political philosophy, and the pragmatist tradition.' },
    { question: 'What did John Dewey believe?', answer: 'John Dewey believed that ideas are not mental photographs of the world but instruments or tools for solving problems, a position he called instrumentalism. He argued that democracy is not simply a system of government but a way of life requiring citizens who can think critically, collaborate, and adapt. He held that education should be based on learning through experience and inquiry rather than rote memorization, and that the classroom should function as a miniature democratic community where students learn by doing.' },
    { question: 'Why is John Dewey important?', answer: 'John Dewey reshaped American education by arguing that learning occurs through active experience and collaborative problem-solving rather than passive absorption of authority, inspiring progressive education movements, project-based learning, and inquiry-based science education worldwide. He completed the pragmatist revolution begun by Peirce and James by reconceiving knowledge as the product of active inquiry, dissolving traditional philosophical dualisms between mind and body, theory and practice, and fact and value. His analysis of democratic dysfunction and the lost public anticipated contemporary debates about media fragmentation and civic disengagement.' },
    { question: "What are John Dewey's major works?", answer: "John Dewey's Democracy and Education (1916) is his most influential work, arguing that education should cultivate democratic habits through experience and inquiry rather than rote memorization. Experience and Nature (1925) lays out his naturalistic metaphysics, while The Quest for Certainty (1929) critiques the traditional philosophical search for absolute foundations of knowledge. Art as Experience (1934) presents his aesthetics, arguing that art is continuous with ordinary experience rather than confined to museums and galleries." },
    { question: "What is Dewey's philosophy of education?", answer: "John Dewey's philosophy of education holds that genuine learning occurs only through reflective experience, where the learner connects what they do to what happens as a result. He argued that children should not be trained to obey but educated to think, identifying problems, forming hypotheses, testing them, and revising their beliefs. He maintained that the method of education determines the kind of society that emerges from it: schools organized around obedience produce citizens suited to autocracy, while schools organized around shared inquiry and collaborative problem-solving produce citizens capable of democratic participation." },
  ],
  'w-e-b-du-bois': [
    { question: 'Who was W.E.B. Du Bois?', answer: 'W.E.B. Du Bois was an American philosopher, sociologist, historian, and civil rights leader born in 1868 who became the first African American to earn a doctorate from Harvard. He challenged Booker T. Washington\'s program of accommodation and co-founded the NAACP, becoming one of the most influential African American intellectuals of the twentieth century. His career spanned decades of scholarship and activism, and he died in Ghana in 1963 on the eve of the March on Washington.' },
    { question: 'What did W.E.B. Du Bois believe?', answer: 'W.E.B. Du Bois believed that the problem of the twentieth century is the problem of the color line, and that racial oppression is not merely a matter of individual prejudice but a structural feature of the political economy. He argued that African Americans experience a double consciousness, seeing themselves simultaneously through their own eyes and through the contemptuous eyes of a racist white society. He insisted that political rights and liberal education are preconditions for genuine equality, not luxuries to be deferred, and that the most educated members of the Black community have a responsibility to provide intellectual and political leadership.' },
    { question: 'Why is W.E.B. Du Bois important?', answer: 'W.E.B. Du Bois pioneered the philosophy of race and reshaped American thought about identity, democracy, and justice. His concept of double consciousness anticipated by decades the insight that marginalized social positions can generate distinctive forms of knowledge, an idea now central to standpoint epistemology and critical race theory. His Black Reconstruction in America demonstrated that what counts as history is shaped by the interests of those who write it, a methodological insight that influenced critical theory, postcolonial studies, and the sociology of knowledge.' },
    { question: "What are W.E.B. Du Bois's major works?", answer: "W.E.B. Du Bois's The Souls of Black Folk (1903) is his most celebrated work, introducing the concept of double consciousness and the metaphor of the color line that defined debates about race in America. Black Reconstruction in America (1935) challenged the prevailing racist narrative of the Reconstruction era, arguing that Black Americans created the first genuinely democratic governments the South had ever known. Darkwater (1920) combined essays, fiction, and poetry to explore race, gender, and imperialism from a global perspective." },
    { question: "What is Du Bois's concept of double consciousness?", answer: "W.E.B. Du Bois's concept of double consciousness describes the experience of African Americans seeing themselves simultaneously through their own eyes and through the contemptuous eyes of a racist white society, a divided self-awareness he called a peculiar twoness. This forced doubling of awareness is a burden imposed by structural inequality, since the Black American must constantly monitor how they appear to white observers while maintaining their own sense of identity. However, Du Bois also argued that this divided perspective is a source of unique insight, since the person who lives on both sides of the color line understands both worlds in a way that someone on only one side cannot." },
  ],

  'bertrand-russell': [
    { question: 'Who was Bertrand Russell?', answer: 'Bertrand Russell (1872-1970) was a British philosopher, mathematician, logician, and Nobel laureate who co-founded analytic philosophy. He made groundbreaking contributions to mathematical logic through Principia Mathematica, written with Alfred North Whitehead, and was also a prominent political activist and public intellectual throughout his long life.' },
    { question: 'What did Bertrand Russell believe?', answer: 'Bertrand Russell believed that philosophy should achieve the clarity and rigor of mathematics and logic. He championed logical analysis as a method for dissolving philosophical problems, argued that ordinary language systematically misleads us about the structure of reality, and maintained that rationality and empirical evidence should guide both intellectual inquiry and social life.' },
    { question: 'Why is Bertrand Russell important?', answer: 'Bertrand Russell is important because he co-founded the analytic philosophy tradition that came to dominate English-speaking philosophy departments. He won the Nobel Prize in Literature, discovered a paradox that reshaped the foundations of mathematics, and pioneered the use of logical analysis to resolve philosophical problems.' },
    { question: "What are Bertrand Russell's major works?", answer: "Bertrand Russell's major works include Principia Mathematica (with Whitehead), The Problems of Philosophy, History of Western Philosophy, Why I Am Not a Christian, and the influential paper On Denoting. These works span mathematical logic, epistemology, social commentary, and the philosophy of language." },
    { question: "What is Russell's Paradox?", answer: "Russell's Paradox, discovered in 1901, asks whether the set of all sets that do not contain themselves contains itself. If it does, then by definition it should not; if it does not, then it should. This contradiction revealed a fundamental flaw in naive set theory and forced a complete reconstruction of the foundations of mathematics." },
  ],
  'edmund-husserl': [
    { question: 'Who was Edmund Husserl?', answer: 'Edmund Husserl (1859-1938) was a German philosopher who founded phenomenology, the rigorous and systematic study of consciousness and its objects. He developed groundbreaking methods for examining how things appear to consciousness, influencing virtually all subsequent continental philosophy, cognitive science, and numerous other fields.' },
    { question: 'What did Edmund Husserl believe?', answer: 'Edmund Husserl believed that philosophy must return to the things themselves by studying the structures of conscious experience. He argued that by bracketing assumptions about the external world through a method called the epoche, we can describe how meaning is constituted in consciousness and uncover the essential structures of experience.' },
    { question: 'Why is Edmund Husserl important?', answer: 'Edmund Husserl is important because he founded phenomenology, creating an entirely new philosophical method. His work directly influenced Heidegger, Sartre, Merleau-Ponty, Derrida, and the development of cognitive science, making him one of the most consequential philosophers of the 20th century.' },
    { question: "What are Edmund Husserl's major works?", answer: "Edmund Husserl's major works include Logical Investigations, Ideas I, Cartesian Meditations, and The Crisis of European Sciences. These works develop his phenomenological method from its earliest formulations through its mature application to the crisis of meaning in modern scientific civilization." },
    { question: "What is Husserl's phenomenological reduction?", answer: "Husserl's phenomenological reduction, or epoche, is a method in which the philosopher suspends all assumptions about whether the objects of experience actually exist in an external world. This does not deny the external world but sets it aside, revealing the essential structures of how things appear to consciousness and how meaning is constituted." },
  ],
  'martin-heidegger': [
    { question: 'Who was Martin Heidegger?', answer: 'Martin Heidegger (1889-1976) was a German philosopher whose Being and Time is one of the most important and difficult works of 20th-century philosophy. He was a member of the Nazi Party, and his private journals reveal antisemitism woven into his philosophical worldview, making the relationship between his philosophy and his politics a genuinely unresolved question.' },
    { question: 'What did Martin Heidegger believe?', answer: 'Martin Heidegger believed that the fundamental question of philosophy is the question of Being, which Western philosophy had forgotten to ask. He argued that human existence (Dasein) is uniquely characterized by its concern for its own being and its awareness of mortality, and that we are always already embedded in a world of meaning rather than being detached observers.' },
    { question: 'Why is Martin Heidegger important?', answer: 'Martin Heidegger is important because Being and Time reframed the entire history of Western philosophy and shaped existentialism, hermeneutics, deconstruction, and environmental philosophy. His analysis of technology, authenticity, and human existence influenced theology, psychology, literary theory, and cognitive science.' },
    { question: "What are Martin Heidegger's major works?", answer: "Martin Heidegger's major works include Being and Time, Introduction to Metaphysics, The Question Concerning Technology, and Poetry, Language, Thought. Being and Time remains his most influential work, while his later essays on technology and language developed new directions in his thought." },
    { question: "What is Heidegger's concept of Being-toward-Death?", answer: "Heidegger's Being-toward-Death holds that authentic existence requires confronting our own mortality directly. In everyday life we flee from death by taking refuge in anonymous social conventions, but only by facing the certainty of death can we be liberated from conformity and genuinely engage with our own finite existence." },
  ],
  'ludwig-wittgenstein': [
    { question: 'Who was Ludwig Wittgenstein?', answer: 'Ludwig Wittgenstein (1889-1951) was an Austrian-British philosopher who produced two distinct and incompatible philosophies, each of which reshaped analytic philosophy. His early Tractatus Logico-Philosophicus proposed that language pictures reality, while his later Philosophical Investigations argued that meaning arises from use in social practices he called language games.' },
    { question: 'What did Ludwig Wittgenstein believe?', answer: 'Ludwig Wittgenstein believed that the limits of language mean the limits of the world. In his later philosophy, he argued that words gain meaning through use within specific forms of life, not through fixed definitions, and that many traditional philosophical problems arise from taking words out of the contexts that give them meaning.' },
    { question: 'Why is Ludwig Wittgenstein important?', answer: 'Ludwig Wittgenstein is important because he reshaped analytic philosophy twice, first with the picture theory of meaning and then with the concept of language games. His work transformed the philosophy of language, philosophy of mind, and our understanding of the relationship between language and reality.' },
    { question: "What are Ludwig Wittgenstein's major works?", answer: "Ludwig Wittgenstein's major works include the Tractatus Logico-Philosophicus, Philosophical Investigations, On Certainty, and the Blue and Brown Books. The Tractatus and the Investigations represent his two incompatible philosophies, making his career uniquely dramatic in the history of thought." },
    { question: "What are Wittgenstein's language games?", answer: "Wittgenstein's language games are the diverse activities and contexts through which words gain their meaning. He argued that there is no single essence of language, but rather an indefinite variety of uses, each with its own rules and purposes. Many philosophical problems arise from mistakenly taking words out of the language games that give them meaning." },
  ],
  'hannah-arendt': [
    { question: 'Who was Hannah Arendt?', answer: 'Hannah Arendt (1906-1975) was a German-born American political philosopher who fled Nazi Germany and became one of the leading political thinkers of the 20th century. She studied under Heidegger and Jaspers, and her works on totalitarianism, political action, and the nature of evil profoundly shaped political philosophy.' },
    { question: 'What did Hannah Arendt believe?', answer: 'Hannah Arendt believed that evil is often the product of thoughtlessness rather than demonic intent, and that political freedom requires active citizen participation. She argued that totalitarianism is a genuinely new form of government that seeks total domination over every dimension of human life, and that thinking itself is a moral act.' },
    { question: 'Why is Hannah Arendt important?', answer: 'Hannah Arendt is important because she reshaped political philosophy with her analysis of totalitarianism, her concept of the banality of evil, and her theory of political action. Her insights into how isolation, atomization, and the collapse of civic institutions create conditions for tyranny remain regularly invoked in contemporary debates.' },
    { question: "What are Hannah Arendt's major works?", answer: "Hannah Arendt's major works include The Origins of Totalitarianism, The Human Condition, Eichmann in Jerusalem, On Revolution, and The Life of the Mind. Each work addresses fundamental questions about political life, freedom, evil, and the conditions for human flourishing in the modern world." },
    { question: "What is Arendt's banality of evil?", answer: "Hannah Arendt's banality of evil describes how the worst atrocities can be perpetrated by ordinary, thoughtless people rather than sadistic monsters. Observing Adolf Eichmann's trial, she found not a fanatic but a shallow bureaucrat incapable of independent moral judgment, revealing that the failure to think is itself a form of moral catastrophe." },
  ],
  'jean-paul-sartre': [
    { question: 'Who was Jean-Paul Sartre?', answer: 'Jean-Paul Sartre (1905-1980) was a French philosopher, novelist, and playwright who became the most publicly famous philosopher of the 20th century. He developed existentialism into a comprehensive philosophy centered on radical human freedom, authored the dense philosophical work Being and Nothingness, and was awarded but refused the Nobel Prize in Literature in 1964.' },
    { question: 'What did Jean-Paul Sartre believe?', answer: 'Jean-Paul Sartre believed that existence precedes essence, meaning that human beings have no predetermined nature and must create themselves through their choices. He argued that we are condemned to be free, that bad faith is our tendency to deny this freedom, and that we bear total responsibility for who we become.' },
    { question: 'Why is Jean-Paul Sartre important?', answer: 'Jean-Paul Sartre is important because he made philosophy a public enterprise and articulated the defining principles of existentialism. His influence extended across literature, politics, feminism (through his partnership with Simone de Beauvoir), and culture, shaping how an entire generation understood freedom and responsibility.' },
    { question: "What are Jean-Paul Sartre's major works?", answer: "Jean-Paul Sartre's major works include Being and Nothingness, Existentialism is a Humanism, the novel Nausea, the play No Exit, and Critique of Dialectical Reason. These span philosophy, fiction, drama, and political theory, demonstrating his extraordinary range as a thinker and writer." },
    { question: "What is Sartre's concept of bad faith?", answer: "Sartre's bad faith (mauvaise foi) is a form of self-deception in which people deny their own freedom by pretending they have no choice. Examples include identifying so completely with a social role that one treats it as a fixed nature, or claiming that emotions or circumstances compel behavior. Bad faith is the default human condition because confronting radical freedom produces unbearable anxiety." },
  ],
  'simone-de-beauvoir': [
    { question: 'Who was Simone de Beauvoir?', answer: 'Simone de Beauvoir (1908-1986) was a French existentialist philosopher, novelist, and feminist thinker whose work The Second Sex is the founding text of modern feminist philosophy. She applied existentialist philosophy to the situation of women, producing groundbreaking analyses of gender, freedom, and oppression that transformed 20th-century thought.' },
    { question: 'What did Simone de Beauvoir believe?', answer: 'Simone de Beauvoir believed that one is not born but rather becomes a woman, arguing that femininity is socially constructed rather than biologically determined. She held that throughout history man has been defined as the Subject while woman is defined as the Other, and that genuine freedom requires solidarity with the oppressed.' },
    { question: 'Why is Simone de Beauvoir important?', answer: 'Simone de Beauvoir is important because she pioneered feminist philosophy and provided the intellectual foundation for second-wave feminism and gender studies. Her distinction between biological sex and socially constructed gender became a fundamental analytical tool across the social sciences and humanities.' },
    { question: "What are Simone de Beauvoir's major works?", answer: "Simone de Beauvoir's major works include The Second Sex, The Ethics of Ambiguity, the novel She Came to Stay, the autobiographical Memoirs of a Dutiful Daughter, and The Coming of Age. The Second Sex remains one of the most influential works of philosophy published in the 20th century." },
    { question: "What does de Beauvoir mean by 'One is not born, but rather becomes, a woman'?", answer: "Simone de Beauvoir meant that femininity is not a biological destiny but a social construction. From birth, girls are taught to be passive, nurturing, and self-sacrificing through education, custom, and social pressure. There is no eternal feminine nature; there are only roles that society assigns to women and calls natural." },
  ],
  'albert-camus': [
    { question: 'Who was Albert Camus?', answer: 'Albert Camus (1913-1960) was a French-Algerian philosopher, novelist, and Nobel Prize-winning author who developed the philosophy of Absurdism. He argued that life is absurd but worth living, and his break with Sartre over revolutionary violence became one of the defining intellectual conflicts of the 20th century.' },
    { question: 'What did Albert Camus believe?', answer: 'Albert Camus believed that the confrontation between our desperate need for meaning and the universe\'s indifferent silence creates the Absurd. Rather than choosing suicide or religious faith, he advocated revolt, living fully and defiantly in the face of meaninglessness, insisting that rebellion must respect moral limits.' },
    { question: 'Why is Albert Camus important?', answer: 'Albert Camus is important because he offered a powerful philosophical response to nihilism that continues to inspire millions. His Nobel Prize-winning literary works, his philosophy of the Absurd, and his moral stand against revolutionary violence influenced existentialist thought, literature, and political philosophy.' },
    { question: "What are Albert Camus's major works?", answer: "Albert Camus's major works include The Myth of Sisyphus, The Stranger, The Plague, The Rebel, and The Fall. These span philosophical essays and novels, each exploring themes of absurdity, meaning, revolt, and the moral limits of political action." },
    { question: 'What is the Myth of Sisyphus about?', answer: 'The Myth of Sisyphus uses the figure of Sisyphus, condemned to roll a boulder uphill for eternity only to watch it roll back down, as the hero of the Absurd. Camus argues we must imagine Sisyphus happy because his conscious defiance of a meaningless fate, his refusal to surrender, transforms mere suffering into a form of human dignity.' },
  ],
  'michel-foucault': [
    { question: 'Who was Michel Foucault?', answer: 'Michel Foucault (1926-1984) was a French philosopher and historian of ideas who examined how institutions like prisons, hospitals, and schools produce and enforce norms about truth, normality, and sanity. He became one of the most cited scholars in the humanities, and his genealogical method revealed hidden power dynamics in seemingly neutral systems of knowledge.' },
    { question: 'What did Michel Foucault believe?', answer: 'Michel Foucault believed that power and knowledge are inseparable, and that every system of knowledge enables new forms of social control. He argued that modern society controls people not primarily through violence but through discipline, subtle techniques of observation and normalization that train individuals to regulate themselves.' },
    { question: 'Why is Michel Foucault important?', answer: 'Michel Foucault is important because he changed how we understand institutions, discourse, truth, and the relationship between knowledge and social control. His analysis of surveillance and disciplinary power anticipated debates about digital privacy and the modern surveillance state by decades.' },
    { question: "What are Michel Foucault's major works?", answer: "Michel Foucault's major works include Discipline and Punish, The History of Sexuality, Madness and Civilization, The Order of Things, and The Archaeology of Knowledge. Each work examines how categories we take for granted are products of specific historical power relations rather than timeless truths." },
    { question: "What is Foucault's concept of power/knowledge?", answer: "Foucault's power/knowledge thesis holds that power and knowledge directly imply one another. Every exercise of power creates new knowledge, and every system of knowledge enables new forms of power. There is no neutral truth outside of power relations; the institutions that claim to know us best are often the ones that control us most effectively." },
  ],
  'jacques-derrida': [
    { question: 'Who was Jacques Derrida?', answer: 'Jacques Derrida (1930-2004) was a French philosopher who developed deconstruction, a method of reading that reveals hidden assumptions, contradictions, and hierarchies within texts and systems of thought. His work transformed literary criticism, legal theory, architecture, and continental philosophy.' },
    { question: 'What did Jacques Derrida believe?', answer: 'Jacques Derrida believed that meaning is never fully present but always deferred through a play of differences. He argued that Western philosophy rests on binary oppositions that privilege one term while marginalizing the other, and that careful reading reveals how these hierarchies collapse under scrutiny.' },
    { question: 'Why is Jacques Derrida important?', answer: 'Jacques Derrida is important because he founded deconstruction, which became one of the most influential intellectual movements of the late 20th century. His challenge to the Western philosophical tradition\'s desire for fixed foundations and stable meanings reshaped how scholars across multiple disciplines approach texts and meaning.' },
    { question: "What are Jacques Derrida's major works?", answer: "Jacques Derrida's major works include Of Grammatology, Writing and Difference, Margins of Philosophy, Specters of Marx, and The Gift of Death. Three of his most important works were all published in 1967, collectively mounting a sustained challenge to the Western philosophical tradition." },
    { question: "What is Derrida's differance?", answer: "Derrida's differance (deliberately misspelled) names the process by which meaning is produced through an interplay of differences and deferrals that never arrives at a final, stable signification. Every sign means what it means by virtue of its difference from other signs, and every attempt to fix meaning generates further differences that postpone closure." },
  ],
  'john-rawls': [
    { question: 'Who was John Rawls?', answer: 'John Rawls (1921-2002) was an American political philosopher whose A Theory of Justice is the most important work of political philosophy published in the 20th century. He spent most of his career at Harvard, where he revitalized the social contract tradition and provided a systematic alternative to both utilitarian and libertarian theories of justice.' },
    { question: 'What did John Rawls believe?', answer: 'John Rawls believed that a just society is one we would design from behind a veil of ignorance about our own position in it. He argued that rational people who did not know whether they would be rich or poor would choose principles that protect basic liberties and ensure that inequalities benefit the least advantaged members of society.' },
    { question: 'Why is John Rawls important?', answer: 'John Rawls is important because he revitalized political philosophy with a rigorous framework for evaluating justice. His theory influenced law, policy, economics, and global governance, and his debate with Robert Nozick defined the terms of political philosophy for a generation.' },
    { question: "What are John Rawls's major works?", answer: "John Rawls's major works include A Theory of Justice, Political Liberalism, The Law of Peoples, and Justice as Fairness: A Restatement. A Theory of Justice revived the social contract tradition, while Political Liberalism addressed how deeply divided societies can maintain political unity." },
    { question: "What is Rawls's veil of ignorance?", answer: "Rawls's veil of ignorance is a thought experiment in which people design the rules of society without knowing their own position in it, including their race, sex, talents, wealth, or conception of the good life. Because rational choosers would not gamble on ending up at the bottom, they would select principles that treat everyone fairly regardless of circumstance." },
  ],
  'karl-popper': [
    { question: 'Who was Karl Popper?', answer: 'Karl Popper (1902-1994) was an Austrian-British philosopher of science and political philosopher who argued that the hallmark of genuine science is falsifiability. He also championed the open society against authoritarianism of all kinds, providing philosophical foundations for liberal democratic resistance to totalitarianism.' },
    { question: 'What did Karl Popper believe?', answer: 'Karl Popper believed that science advances through falsification, not verification. A theory must be testable and potentially refutable to count as scientific. In political philosophy, he argued that open societies relying on free criticism and piecemeal reform are superior to utopian projects that claim to know the direction of history.' },
    { question: 'Why is Karl Popper important?', answer: 'Karl Popper is important because he reshaped the philosophy of science with his falsificationism and provided the philosophical underpinning for anti-totalitarian liberalism. His demarcation criterion between science and non-science remains the starting point for discussions of scientific methodology worldwide.' },
    { question: "What are Karl Popper's major works?", answer: "Karl Popper's major works include The Logic of Scientific Discovery, The Open Society and Its Enemies, Conjectures and Refutations, and The Poverty of Historicism. Together they address both the philosophy of science and political philosophy, unified by a commitment to critical rationalism." },
    { question: "What is Popper's falsifiability principle?", answer: "Popper's falsifiability principle holds that a theory is scientific if and only if it can be tested and potentially proven wrong. Einstein's relativity made risky predictions that could have been falsified, making it genuinely scientific. Theories like Marxism or Freudianism, which can accommodate any possible observation, are unfalsifiable and therefore not scientific in Popper's sense." },
  ],
  'john-searle': [
    { question: 'Who was John Searle?', answer: 'John Searle (1932-2025) was an American philosopher who spent over five decades at UC Berkeley, making major contributions to the philosophy of language, philosophy of mind, and the theory of social reality. He is best known for the Chinese Room argument, which challenged the foundations of artificial intelligence research.' },
    { question: 'What did John Searle believe?', answer: 'John Searle believed that syntax is not sufficient for semantics, meaning that a computer manipulating symbols according to rules does not genuinely understand anything. He also held that consciousness is a real biological phenomenon caused by brain processes, and that social institutions are constructed through collective agreement expressed in language.' },
    { question: 'Why is John Searle important?', answer: 'John Searle is important because his Chinese Room argument remains central to debates about artificial intelligence and consciousness, his speech act theory transformed the philosophy of language, and his account of institutional reality explained how social facts like money and marriage are constructed through collective agreement.' },
    { question: "What are John Searle's major works?", answer: "John Searle's major works include Speech Acts, Intentionality, The Construction of Social Reality, and The Rediscovery of the Mind. These works span the philosophy of language, philosophy of mind, and social ontology, each making foundational contributions to its field." },
    { question: "What is Searle's Chinese Room argument?", answer: "Searle's Chinese Room imagines a person sealed in a room who receives Chinese characters and uses a rulebook to send back appropriate responses, without understanding Chinese. Searle argued that this is exactly what a computer does: it manipulates symbols according to formal rules without any genuine understanding. Therefore, a computer program alone cannot produce a mind." },
  ],
  'simone-weil': [
    { question: 'Who was Simone Weil?', answer: 'Simone Weil (1909-1943) was a French philosopher, mystic, and political activist whose brief life produced some of the most arresting philosophical writing of the 20th century. She worked in factories and joined fighters in the Spanish Civil War to understand suffering firsthand, and her philosophy centers on attention as the foundation of ethics and spiritual life.' },
    { question: 'What did Simone Weil believe?', answer: 'Simone Weil believed that attention, the selfless and receptive openness to reality and other people, is the rarest and purest form of generosity. She argued that the core moral capacity is the ability to look steadily at reality without flinching or self-deception, and that this capacity is simultaneously ethical, intellectual, and spiritual.' },
    { question: 'Why is Simone Weil important?', answer: 'Simone Weil is important because her concept of attention as the foundation of moral life directly influenced Iris Murdoch, Emmanuel Levinas, and contemporary philosophies of care. Albert Camus called her the only great spirit of their times, and her analysis of affliction remains one of the most penetrating accounts of suffering in philosophical literature.' },
    { question: "What are Simone Weil's major works?", answer: "Simone Weil's major works include Gravity and Grace, The Need for Roots, Waiting for God, and her Notebooks. Most were published posthumously, as she died at thirty-four. The Need for Roots was commissioned by the Free French government as a plan for France's moral reconstruction after liberation." },
    { question: "What is Weil's concept of attention?", answer: "Simone Weil's concept of attention is the ability to look steadily at reality and other people without imposing our own narratives or self-interest. It requires suspending the ego to simply see what is truly there. Weil argued that this same capacity underlies ethics, intellectual life, and spiritual practice, making attention the foundation of both justice and love." },
  ],
  'isaiah-berlin': [
    { question: 'Who was Isaiah Berlin?', answer: 'Isaiah Berlin (1909-1997) was a Latvian-born British philosopher who became the 20th century\'s most eloquent defender of liberalism and value pluralism. A professor at Oxford, he argued that human values are genuinely plural and sometimes incompatible, grounding a liberalism that cherishes freedom precisely because reasonable people disagree about the good life.' },
    { question: 'What did Isaiah Berlin believe?', answer: 'Isaiah Berlin believed that the deepest human values, such as liberty, equality, justice, and community, are genuinely plural and sometimes irreconcilably in conflict. He argued that the belief that all good things can be harmonized in a perfect society is a dangerous illusion, and that political freedom is essential because there is no single right way to live.' },
    { question: 'Why is Isaiah Berlin important?', answer: 'Isaiah Berlin is important because he defined modern liberalism\'s core commitments and articulated value pluralism as a challenge to the entire Western philosophical tradition. His distinction between negative and positive liberty became the most widely assigned reading in 20th-century political philosophy.' },
    { question: "What are Isaiah Berlin's major works?", answer: "Isaiah Berlin's major works include Two Concepts of Liberty, The Hedgehog and the Fox, Four Essays on Liberty, and The Roots of Romanticism. Two Concepts of Liberty is the most widely discussed text in postwar political philosophy, and The Hedgehog and the Fox introduced an enduring typology of intellectual styles." },
    { question: "What are Berlin's two concepts of liberty?", answer: "Isaiah Berlin distinguished negative liberty, freedom from interference by others, from positive liberty, the freedom to realize one's true self. He warned that positive liberty contains a fatal danger: if authorities claim to know your real will better than you do, they can coerce you in the name of your own freedom, a pattern he traced through the history of tyranny." },
  ],
  'maurice-merleau-ponty': [
    { question: 'Who was Maurice Merleau-Ponty?', answer: 'Maurice Merleau-Ponty (1908-1961) was a French phenomenologist who argued that Western philosophy made a catastrophic error by separating mind from body. His Phenomenology of Perception challenged Cartesian dualism by showing that consciousness is always embodied and that perception is the foundation of all knowledge.' },
    { question: 'What did Maurice Merleau-Ponty believe?', answer: 'Maurice Merleau-Ponty believed that we do not have bodies but rather are our bodies, and that perception is the foundation of all knowledge. He argued that our primary relationship to the world is practical and bodily, not theoretical and intellectual, and that scientific models are abstractions from the richer world of lived experience.' },
    { question: 'Why is Maurice Merleau-Ponty important?', answer: 'Maurice Merleau-Ponty is important because he bridged philosophy and cognitive science, reshaping how we understand perception and mind. His work on embodied cognition influenced robotics, AI research, phenomenological psychology, and the philosophy of sport, dance, and skilled action.' },
    { question: "What are Maurice Merleau-Ponty's major works?", answer: "Maurice Merleau-Ponty's major works include Phenomenology of Perception, The Visible and the Invisible, and The Structure of Behavior. Phenomenology of Perception remains his masterwork, while The Visible and the Invisible, left unfinished at his death, develops a bold new ontology of flesh and reversibility." },
    { question: "What is Merleau-Ponty's theory of embodied perception?", answer: "Merleau-Ponty's theory of embodied perception holds that perception is not the mind passively receiving data but the body actively engaging with its environment. We see a cup not as abstract visual data but as something to be grasped, at a certain distance from our hand. The body is not a machine housing the mind but the very medium through which the world becomes available to us." },
  ],
  'frantz-fanon': [
    { question: 'Who was Frantz Fanon?', answer: 'Frantz Fanon (1925-1961) was a Martinique-born psychiatrist and philosopher who produced searing analyses of colonialism, racism, and liberation. Trained in France and radicalized by the Algerian War of Independence, he argued that colonial domination is not just economic or political but psychological, deforming the consciousness of both colonizer and colonized.' },
    { question: 'What did Frantz Fanon believe?', answer: 'Frantz Fanon believed that colonialism is a comprehensive assault on the consciousness of the colonized, imposing a racial hierarchy that the colonized person internalizes. He argued that liberation requires not just political independence but a radical reconstruction of selfhood, and that decolonization is necessarily a violent process when colonial powers refuse to leave peacefully.' },
    { question: 'Why is Frantz Fanon important?', answer: 'Frantz Fanon is important because he founded postcolonial philosophy and provided the intellectual framework for liberation movements across Africa, Asia, and Latin America. His insight that domination operates through consciousness, not just force and economics, transformed how scholars and activists understand power.' },
    { question: "What are Frantz Fanon's major works?", answer: "Frantz Fanon's major works include Black Skin, White Masks and The Wretched of the Earth, along with A Dying Colonialism. Black Skin, White Masks analyzes the psychology of colonized consciousness, while The Wretched of the Earth addresses the process and politics of decolonization." },
    { question: "What is Fanon's concept of colonial consciousness?", answer: "Fanon's concept of colonial consciousness describes how the colonized person internalizes the colonizer's racial hierarchy, experiencing their own identity as inferior and their culture as backward. The colonized adopts the language and aspirations of the colonizer in a futile attempt to escape racial categorization, but the colonial system will never accept them as fully human." },
  ],
  'iris-murdoch': [
    { question: 'Who was Iris Murdoch?', answer: 'Iris Murdoch (1919-1999) was a British philosopher and novelist who challenged the dominant Anglo-American moral philosophy of her time. While her peers focused on rules and logical analysis, Murdoch insisted that morality is fundamentally about perception, about seeing other people clearly without the distortions of ego and self-interest.' },
    { question: 'What did Iris Murdoch believe?', answer: 'Iris Murdoch believed that morality is not about dramatic choices but about the quality of attention we pay to reality. She argued that the really important moral work happens before the moment of choice, in the slow effort to see other people justly, and that beauty has genuine moral power because it forces us out of our self-concern.' },
    { question: 'Why is Iris Murdoch important?', answer: 'Iris Murdoch is important because she revived Platonic ethics in the modern era and single-handedly restored the inner life to moral philosophy. Her concept of moral attention influenced the ethics of care, contemporary virtue ethics, and moral psychology, and her novels are among the finest of the 20th century.' },
    { question: "What are Iris Murdoch's major works?", answer: "Iris Murdoch's major philosophical works include The Sovereignty of Good, Metaphysics as a Guide to Morals, and The Fire and the Sun. The Sovereignty of Good is a landmark of 20th-century moral philosophy. She also wrote over twenty acclaimed novels that demonstrate the moral attention she advocated." },
    { question: "What is Murdoch's concept of moral attention?", answer: "Iris Murdoch's moral attention is the disciplined effort to see other people and reality clearly, without the distortions of selfishness, anxiety, and fantasy. She illustrated this with a mother-in-law who, through sustained attentive effort, comes to see her daughter-in-law as warm rather than vulgar. The moral transformation is entirely in perception, not in outward behavior." },
  ],
  'philippa-foot': [
    { question: 'Who was Philippa Foot?', answer: 'Philippa Foot (1920-2010) was an English philosopher who helped revive Aristotelian virtue ethics within the analytic tradition and invented the trolley problem, one of the most widely discussed thought experiments in modern ethics. She worked at Somerville College, Oxford, alongside Elizabeth Anscombe and Iris Murdoch.' },
    { question: 'What did Philippa Foot believe?', answer: 'Philippa Foot believed that moral goodness is a form of natural goodness, evaluable in the same way we assess whether a plant or animal is functioning well as a member of its species. She argued that the virtues, such as courage, justice, and temperance, are rationally grounded human necessities for flourishing, not mere expressions of feeling.' },
    { question: 'Why is Philippa Foot important?', answer: 'Philippa Foot is important because she helped launch the modern revival of Aristotelian virtue ethics as a serious alternative to utilitarianism and Kantian deontology. She also invented the trolley problem, which has become central to moral psychology, neuroscience, and the ethics of autonomous vehicles.' },
    { question: "What are Philippa Foot's major works?", answer: "Philippa Foot's major works include Virtues and Vices, Natural Goodness, and Moral Dilemmas. Natural Goodness provides her fullest account of moral goodness as continuous with natural goodness in living things. Her 1967 paper on the doctrine of double effect introduced what became the trolley problem." },
    { question: 'What is the trolley problem?', answer: 'The trolley problem, introduced by Philippa Foot, asks whether you should divert a runaway trolley to kill one person instead of five. Most people say yes. But in a variant where you must push someone off a bridge to stop the trolley, most people recoil, despite identical arithmetic. The problem exposes a deep tension between consequentialist reasoning and deontological moral intuitions.' },
  ],
  'jurgen-habermas': [
    { question: 'Who is Jurgen Habermas?', answer: 'Jurgen Habermas (born 1929) is a German philosopher and the most important social philosopher of the late 20th century. He developed a comprehensive theory of communicative reason, arguing that truth and legitimacy emerge from open, egalitarian dialogue free from coercion, and provided philosophical foundations for deliberative democracy and human rights.' },
    { question: 'What does Jurgen Habermas believe?', answer: 'Jurgen Habermas believes that legitimate norms are those that could be agreed to by all affected persons in free, rational discourse. He argues that the primary function of language is achieving mutual understanding, and that modern society faces a crisis when market logic and bureaucratic power colonize domains of life that depend on genuine human communication.' },
    { question: 'Why is Jurgen Habermas important?', answer: 'Jurgen Habermas is important because his discourse ethics provided the most rigorous philosophical foundation for deliberative democracy. His concept of the public sphere, theory of communicative action, and analysis of how commercial forces degrade public discourse have shaped democratic theory and influenced the institutional design of the European Union.' },
    { question: "What are Jurgen Habermas's major works?", answer: "Jurgen Habermas's major works include The Theory of Communicative Action, The Structural Transformation of the Public Sphere, and Between Facts and Norms. The Theory of Communicative Action is his magnum opus, while The Structural Transformation of the Public Sphere created an entire field of study in media and political theory." },
    { question: "What is Habermas's theory of the public sphere?", answer: "Habermas's public sphere is the domain of social life where private citizens come together as equals to engage in rational debate about matters of public concern. He traced its rise in 18th-century coffeehouses and salons, and warned that it was being colonized by commercial mass media, transforming citizens from participants in rational debate into passive consumers of spectacle." },
  ],
  'robert-nozick': [
    { question: 'Who was Robert Nozick?', answer: 'Robert Nozick (1938-2002) was an American philosopher whose Anarchy, State, and Utopia was the libertarian answer to Rawls\'s egalitarian theory of justice. A professor at Harvard, he argued that individuals have rights so strong that the state may not violate them even for the greater good, and that only a minimal state is morally justified.' },
    { question: 'What did Robert Nozick believe?', answer: 'Robert Nozick believed that justice is about how holdings were acquired, not about how they are distributed. If people acquired their holdings through voluntary exchange and legitimate labor, no government has the right to redistribute them. He argued that taxation for redistribution is on a par with forced labor, and that only a minimal state is justified.' },
    { question: 'Why is Robert Nozick important?', answer: 'Robert Nozick is important because he revitalized libertarian philosophy and forced egalitarians to explain why the state is justified in using coercion to achieve redistributive outcomes. His debate with Rawls defined political philosophy for a generation, and his experience machine thought experiment remains a standard objection to hedonistic utilitarianism.' },
    { question: "What are Robert Nozick's major works?", answer: "Robert Nozick's major works include Anarchy, State, and Utopia, Philosophical Explanations, and The Examined Life. Anarchy, State, and Utopia is his most influential work, presenting the entitlement theory of justice, the Wilt Chamberlain argument, and the experience machine thought experiment." },
    { question: "What is Nozick's experience machine?", answer: "Nozick's experience machine asks whether you would plug into a device that gives you any experience you desire, perfectly realistic but entirely simulated, for the rest of your life. Nozick argued that most people would refuse, revealing that we care about more than just pleasant experiences. We want to actually do things, be certain kinds of people, and live in contact with reality." },
  ],
  'peter-singer': [
    { question: 'Who is Peter Singer?', answer: 'Peter Singer (born 1946) is an Australian moral philosopher widely considered the world\'s most influential living ethicist. His Animal Liberation launched the modern animal rights movement, his work on global poverty argues that affluent people have strong moral obligations to those in extreme need, and he is the intellectual architect of the effective altruism movement.' },
    { question: 'What does Peter Singer believe?', answer: 'Peter Singer believes that if it is in our power to prevent suffering without sacrificing anything of comparable moral importance, we ought to do it. He argues that the capacity to suffer, not species membership, is what matters morally, making factory farming one of the great moral catastrophes of our time, and that geographic distance does not diminish our obligations to the global poor.' },
    { question: 'Why is Peter Singer important?', answer: 'Peter Singer is important because Animal Liberation created the intellectual framework for the modern animal rights movement and made speciesism a standard term in ethical discourse. His drowning child argument provided the foundation for the effective altruism movement, which has channeled billions of dollars toward the most cost-effective charitable interventions.' },
    { question: "What are Peter Singer's major works?", answer: "Peter Singer's major works include Animal Liberation, Practical Ethics, The Life You Can Save, and The Most Good You Can Do. Animal Liberation is the founding text of the animal rights movement, while Practical Ethics became the most widely adopted textbook in applied ethics courses worldwide." },
    { question: "What is Singer's drowning child argument?", answer: "Peter Singer's drowning child argument holds that if you would wade into a pond to save a drowning child, even at the cost of ruining your clothes, the same logic applies to global poverty. People in affluent countries can prevent suffering and death by donating to effective aid organizations at trivial personal cost. Geographic distance and the number of other potential helpers are morally irrelevant." },
  ],
  'martha-nussbaum': [
    { question: 'Who is Martha Nussbaum?', answer: 'Martha Nussbaum (born 1947) is an American philosopher who is prolific and publicly engaged across an unusual range of fields, including ethics, political philosophy, ancient philosophy, feminism, and constitutional law. Her capabilities approach, developed with Amartya Sen, argues that justice requires ensuring every person has the real ability to live a flourishing life.' },
    { question: 'What does Martha Nussbaum believe?', answer: 'Martha Nussbaum believes that human dignity requires not just formal rights but real capabilities, the actual ability to function in central human ways such as living in health, thinking freely, forming relationships, and participating in political life. She also argues that emotions are a form of intelligent moral perception, not obstacles to rational thought.' },
    { question: 'Why is Martha Nussbaum important?', answer: 'Martha Nussbaum is important because the capabilities approach has been adopted by the United Nations as the theoretical framework for the Human Development Index and has influenced constitutional law in India, South Africa, and elsewhere. Her work revived ancient Greek ethics as a living resource for contemporary moral and political philosophy.' },
    { question: "What are Martha Nussbaum's major works?", answer: "Martha Nussbaum's major works include The Fragility of Goodness, Women and Human Development, Upheavals of Thought, Creating Capabilities, and Not for Profit. These span ancient philosophy, feminist theory, the philosophy of emotions, political philosophy, and the philosophy of education." },
    { question: "What is Nussbaum's capabilities approach?", answer: "Martha Nussbaum's capabilities approach holds that a just society must ensure every citizen has the real ability to function in ten central human ways, including living a normal lifespan, enjoying bodily health, using the senses and imagination, forming attachments, and exercising political participation. Formal rights without real capabilities are empty; capabilities are real freedoms, not paper freedoms." },
  ],
  'frank-jackson': [
    { question: 'Who is Frank Jackson?', answer: 'Frank Jackson (born 1943) is an Australian analytic philosopher best known for Mary\'s Room, one of the most discussed thought experiments in the philosophy of mind. He later publicly reversed his own famous argument and became a physicalist, making him one of the rare philosophers to recant a major position.' },
    { question: 'What does Frank Jackson believe?', answer: 'Frank Jackson now believes that physicalism is true, having reversed his earlier view. He originally argued that there are facts about conscious experience that cannot be captured by physical information alone, but he came to conclude that the powerful intuition behind Mary\'s Room is ultimately misleading and that consciousness can be accommodated within a physicalist framework.' },
    { question: 'Why is Frank Jackson important?', answer: 'Frank Jackson is important because his Mary\'s Room thought experiment crystallized the hard problem of consciousness and generated over a thousand published responses. His later recantation of his own argument was itself philosophically significant, demonstrating that even the strongest intuitions about consciousness may mislead us.' },
    { question: "What are Frank Jackson's major works?", answer: "Frank Jackson's major works include Perception: A Representative Theory, From Metaphysics to Ethics, and Mind, Method, and Conditionals. His most influential individual papers are Epiphenomenal Qualia (1982) and What Mary Didn't Know (1986), which introduced the knowledge argument against physicalism." },
    { question: "What is Mary's Room thought experiment?", answer: "Mary's Room imagines a brilliant neuroscientist who has spent her entire life in a black-and-white room but knows every physical fact about color vision. When she leaves and sees red for the first time, she seems to learn something new, what it is like to see red. Jackson originally argued this proves physicalism is false, since physical facts cannot capture all facts about conscious experience." },
  ],
  'michael-oakeshott': [
    { question: 'Who was Michael Oakeshott?', answer: 'Michael Oakeshott (1901-1990) was a British political philosopher and professor at the London School of Economics who articulated a philosophically sophisticated conservatism. He argued that politics is a practice depending on tacit knowledge and inherited skill, not an engineering project amenable to abstract theories and ideological blueprints.' },
    { question: 'What did Michael Oakeshott believe?', answer: 'Michael Oakeshott believed that genuine political knowledge has two components: technical knowledge that can be written in books and practical knowledge that can only be acquired through experience. He argued that the rationalist error of treating all knowledge as technical leads to failed social engineering, and that the state should be a civil association maintaining shared rules rather than pursuing collective goals.' },
    { question: 'Why is Michael Oakeshott important?', answer: 'Michael Oakeshott is important because his critique of rationalism in politics anticipated the failures of central planning and top-down development programs. His distinction between civil and enterprise association provided a deep philosophical basis for limited government, and his metaphor of civilization as a conversation influenced humanistic thought broadly.' },
    { question: "What are Michael Oakeshott's major works?", answer: "Michael Oakeshott's major works include Rationalism in Politics, On Human Conduct, Experience and Its Modes, and The Voice of Liberal Learning. Rationalism in Politics contains his famous critique of technocratic governance, while On Human Conduct develops his distinction between civil and enterprise association." },
    { question: "What is Oakeshott's critique of rationalism in politics?", answer: "Oakeshott argued that the modern rationalist treats political knowledge as entirely technical, as if society can be improved by applying blueprints. But genuine political knowledge includes practical wisdom, judgment, and sensitivity to circumstance that no manual can convey. The rationalist confuses theoretical models with the world itself, producing ideological politics that fails when imposed on complex realities." },
  ],
  'roger-scruton': [
    { question: 'Who was Roger Scruton?', answer: 'Roger Scruton (1944-2020) was a prolific British conservative philosopher who wrote over fifty books on topics from aesthetics and architecture to politics and religion. His core project was articulating a philosophical conservatism grounded in love of home, community, and inherited culture, and he mounted a sustained defense of beauty as an objective value.' },
    { question: 'What did Roger Scruton believe?', answer: 'Roger Scruton believed that conservatism starts from the sentiment that good things are easily destroyed but not easily created. He argued that human flourishing depends on belonging to communities with shared traditions, that beauty is a real and objective value essential to human well-being, and that even secular societies need a sense of the sacred.' },
    { question: 'Why is Roger Scruton important?', answer: 'Roger Scruton is important because he articulated conservative philosophy for a new generation with unmatched philosophical depth. His concept of oikophilia connected conservatism to environmental stewardship, his defense of beauty influenced the architectural traditionalism movement, and his critique of oikophobia provided a framework for understanding cultural divides.' },
    { question: "What are Roger Scruton's major works?", answer: "Roger Scruton's major works include The Meaning of Conservatism, How to Be a Conservative, Beauty, Fools, Frauds and Firebrands, and The Soul of the World. His BBC documentary Why Beauty Matters brought his philosophical arguments about aesthetics to a wide public audience." },
    { question: "What is Scruton's concept of oikophilia?", answer: "Roger Scruton's oikophilia is the love of home, the attachment to familiar places, people, and traditions that forms the root of conservative sentiment. It is not nostalgia but a recognition that human flourishing depends on belonging to a community with shared history. Scruton contrasted it with oikophobia, the pathological rejection of one's own culture that he saw as the characteristic vice of modern intellectuals." },
  ],
  'ayn-rand': [
    { question: 'Who was Ayn Rand?', answer: 'Ayn Rand (1905-1982) was a Russian-born American novelist and philosopher who developed Objectivism, a comprehensive system defending reason, individual rights, and laissez-faire capitalism. Her novels The Fountainhead and Atlas Shrugged sold tens of millions of copies and inspired a philosophical movement that continues to shape American politics and culture.' },
    { question: 'What did Ayn Rand believe?', answer: 'Ayn Rand believed that every person is an end in themselves, not a means to the ends of others. She argued that rational self-interest is a moral virtue, that productive achievement is the central purpose of human life, and that capitalism is the only moral social system because it is the only one that respects individual rights.' },
    { question: 'Why is Ayn Rand important?', answer: 'Ayn Rand is important because her influence on libertarian thought, entrepreneurial culture, and popular philosophy is enormous, even though academic philosophers have often dismissed her. Her novels provided millions of readers with a philosophical framework celebrating productive ambition and individual rights.' },
    { question: "What are Ayn Rand's major works?", answer: "Ayn Rand's major works include the novels Atlas Shrugged and The Fountainhead, and the philosophical works The Virtue of Selfishness, Capitalism: The Unknown Ideal, and Introduction to Objectivist Epistemology. Her novels remain bestsellers decades after publication." },
    { question: "What is Rand's Objectivism?", answer: "Ayn Rand's Objectivism holds that reality exists independently of consciousness, that reason is the only means of knowledge, that rational self-interest is the proper moral purpose of life, and that laissez-faire capitalism is the only just political system. It rejects altruism as a moral doctrine, arguing instead that the individual's own life and happiness are the ultimate values." },
  ],
  'friedrich-hayek': [
    { question: 'Who was Friedrich Hayek?', answer: 'Friedrich Hayek (1899-1992) was an Austrian-British economist and philosopher who won the Nobel Prize in Economics in 1974. He argued that central planning inevitably fails because no authority can possess the dispersed knowledge held by millions of individuals, and that the market price system is an irreplaceable mechanism for coordinating this knowledge.' },
    { question: 'What did Friedrich Hayek believe?', answer: 'Friedrich Hayek believed that the curious task of economics is to demonstrate to people how little they know about what they imagine they can design. He argued that spontaneous orders like markets and common law are superior to planned systems because they harness knowledge dispersed across millions of minds that no central planner can access.' },
    { question: 'Why is Friedrich Hayek important?', answer: 'Friedrich Hayek is important because The Road to Serfdom warned that central economic planning leads inevitably to authoritarianism, a prediction vindicated by the 20th century\'s experiments with socialism. His work on dispersed knowledge and spontaneous order provided the philosophical foundation for free-market economics and influenced Margaret Thatcher, Ronald Reagan, and the global liberalization movement.' },
    { question: "What are Friedrich Hayek's major works?", answer: "Friedrich Hayek's major works include The Road to Serfdom, The Constitution of Liberty, Law, Legislation and Liberty, and The Fatal Conceit. The Road to Serfdom warned against central planning, while The Constitution of Liberty provided a comprehensive defense of classical liberal principles." },
    { question: "What is Hayek's knowledge problem?", answer: "Hayek's knowledge problem holds that the knowledge needed to coordinate a complex economy is dispersed among millions of individuals and cannot be centralized. Market prices aggregate this dispersed knowledge in a way that no central planner can replicate. This is why planned economies fail: they attempt to replace a system that processes vast amounts of local information with a bureaucracy that necessarily possesses only a fraction of it." },
  ],
  'ludwig-von-mises': [
    { question: 'Who was Ludwig von Mises?', answer: 'Ludwig von Mises (1881-1973) was an Austrian economist and philosopher who was an uncompromising defender of classical liberalism and free-market economics. His magnum opus Human Action provided a comprehensive philosophical framework for economics, and his students included Friedrich Hayek, Murray Rothbard, and Israel Kirzner.' },
    { question: 'What did Ludwig von Mises believe?', answer: 'Ludwig von Mises believed that economics is grounded in praxeology, the logical study of purposeful human action. He argued that socialism is not simply inefficient but literally impossible, because without market prices generated by private ownership there is no rational basis for allocating resources among competing uses.' },
    { question: 'Why is Ludwig von Mises important?', answer: 'Ludwig von Mises is important because his economic calculation argument demonstrated that socialist central planning faces an insurmountable knowledge problem, a prediction confirmed by the collapse of planned economies worldwide. He trained a generation of economists and philosophers who shaped the Austrian school of economics and classical liberal thought.' },
    { question: "What are Ludwig von Mises's major works?", answer: "Ludwig von Mises's major works include Human Action, Socialism, Liberalism, and The Anti-Capitalistic Mentality. Human Action is his comprehensive treatise on economics as a science of human action, while Socialism presented his famous argument that rational economic calculation is impossible under socialism." },
    { question: "What is Mises's economic calculation problem?", answer: "Ludwig von Mises's economic calculation problem argues that without private ownership of the means of production, there can be no genuine market prices, and without market prices, there is no rational way to allocate resources among competing uses. Central planners cannot determine whether steel should be used for bridges or trains because they lack the price signals that markets generate through voluntary exchange." },
  ],
  'thomas-kuhn': [
    { question: 'Who was Thomas Kuhn?', answer: 'Thomas Kuhn (1922-1996) was an American physicist turned philosopher of science whose 1962 book The Structure of Scientific Revolutions is one of the most cited academic works of all time. He shattered the myth that science progresses by steady accumulation, introducing the concept of paradigm shifts into both philosophy and everyday language.' },
    { question: 'What did Thomas Kuhn believe?', answer: 'Thomas Kuhn believed that science does not progress through a steady accumulation of facts but through revolutionary upheavals in which one paradigm replaces another. During periods of normal science, researchers solve puzzles within an accepted framework, but anomalies accumulate until a crisis triggers a paradigm shift that fundamentally changes how scientists see the world.' },
    { question: 'Why is Thomas Kuhn important?', answer: 'Thomas Kuhn is important because The Structure of Scientific Revolutions transformed how we understand scientific progress and introduced paradigm shift into everyday language. He challenged the positivist view that science follows a single rational method and influenced philosophy, sociology, history of science, and popular culture.' },
    { question: "What are Thomas Kuhn's major works?", answer: "Thomas Kuhn's major works include The Structure of Scientific Revolutions, The Copernican Revolution, The Essential Tension, and Black-Body Theory and the Quantum Discontinuity. The Structure of Scientific Revolutions remains his most influential work, having been translated into dozens of languages." },
    { question: "What is a Kuhnian paradigm shift?", answer: "A Kuhnian paradigm shift is a scientific revolution in which one fundamental framework for understanding the world is replaced by another. When enough anomalies accumulate that the existing paradigm cannot explain, a crisis occurs, and a new paradigm emerges that restructures the field. Examples include the shift from Ptolemaic to Copernican astronomy and from Newtonian to Einsteinian physics." },
  ],
  'edmund-gettier': [
    { question: 'Who was Edmund Gettier?', answer: 'Edmund Gettier (1927-2021) was an American epistemologist at Wayne State University and later the University of Massachusetts Amherst. In 1963, he published a three-page paper containing two counterexamples that destroyed the 2,400-year-old analysis of knowledge as justified true belief, generating one of the largest literatures in the history of philosophy.' },
    { question: 'What did Edmund Gettier believe?', answer: 'Edmund Gettier demonstrated that justified true belief is not sufficient for knowledge. He showed through counterexamples that a person can have a belief that is both true and justified, yet fails to count as knowledge because the justification connects to the truth only by luck. This challenged an analysis of knowledge accepted in various forms since Plato.' },
    { question: 'Why is Edmund Gettier important?', answer: 'Edmund Gettier is important because his three-page paper generated thousands of articles, dozens of books, and an entirely new subfield of epistemology. He showed that the standard analysis of knowledge that had stood for over two millennia was inadequate, forcing philosophers to fundamentally rethink what knowledge is.' },
    { question: "What are Edmund Gettier's major works?", answer: "Edmund Gettier's major work is the 1963 paper Is Justified True Belief Knowledge?, one of the shortest and most consequential papers in the history of philosophy. Remarkably, Gettier published almost nothing else in his career, reportedly finding the enormous attention his paper generated bewildering." },
    { question: "What is the Gettier problem?", answer: "The Gettier problem shows that knowledge cannot simply be defined as justified true belief. Gettier constructed cases where someone has a justified belief that happens to be true, but only by luck, so it does not count as genuine knowledge. For example, you might see what looks like a sheep in a field and believe there is a sheep there; a sheep is indeed in the field, but what you saw was actually a dog. Your belief is justified and true, but not knowledge." },
  ],
  'derek-parfit': [
    { question: 'Who was Derek Parfit?', answer: 'Derek Parfit (1942-2017) was a British philosopher at All Souls College, Oxford, whose work on personal identity, rationality, and ethics reshaped multiple subfields of philosophy. Born in Chengdu, China, to medical missionary parents, his Reasons and Persons is a landmark of moral philosophy, and On What Matters argued that the major ethical traditions converge.' },
    { question: 'What did Derek Parfit believe?', answer: 'Derek Parfit believed that personal identity is not what matters in survival, that what we care about can be preserved even if strict identity is not. He argued that the three major ethical traditions, consequentialism, Kantianism, and contractualism, are more compatible than their proponents realize and may converge on a single set of moral principles.' },
    { question: 'Why is Derek Parfit important?', answer: 'Derek Parfit is important because his thought experiments about personal identity, teletransportation, and future generations opened entirely new areas of philosophical inquiry. Reasons and Persons is widely considered one of the most important works of moral philosophy in the 20th century, and his attempt to unify ethical theories in On What Matters set the agenda for contemporary moral philosophy.' },
    { question: "What are Derek Parfit's major works?", answer: "Derek Parfit's major works are Reasons and Persons (1984) and On What Matters (2011, 2017). Reasons and Persons transformed the philosophy of personal identity and the ethics of future generations. On What Matters presented his ambitious argument that the three dominant ethical traditions are ultimately compatible." },
    { question: "What is Parfit's view on personal identity?", answer: "Derek Parfit argued that personal identity is not what matters in survival. Through thought experiments involving teletransportation and brain splitting, he showed that what we care about, psychological continuity and connectedness, can hold even when strict identity does not. This has profound implications: it dissolves certain fears about death and strengthens our moral obligations to future people." },
  ],
  'g-e-m-anscombe': [
    { question: 'Who was G.E.M. Anscombe?', answer: 'G.E.M. Anscombe (1919-2001) was a British analytic philosopher who was a student and literary executor of Ludwig Wittgenstein and succeeded to his chair at Cambridge. A fierce and original thinker, she revived virtue ethics, invented the philosophy of action as a field, coined the term consequentialism, and translated Wittgenstein\'s Philosophical Investigations into English.' },
    { question: 'What did G.E.M. Anscombe believe?', answer: 'G.E.M. Anscombe believed that modern moral philosophy had gone fundamentally wrong by trying to retain concepts like moral obligation and moral law while abandoning the divine lawgiver framework that originally gave them meaning. She argued for a return to Aristotelian virtue ethics and pioneered the analysis of intentional action as central to moral philosophy.' },
    { question: 'Why is G.E.M. Anscombe important?', answer: 'G.E.M. Anscombe is important because her 1958 paper Modern Moral Philosophy launched the revival of virtue ethics and coined the term consequentialism. Her book Intention founded the philosophy of action as a distinct field. She also translated Wittgenstein\'s masterwork and was a major interpreter of his thought.' },
    { question: "What are G.E.M. Anscombe's major works?", answer: "G.E.M. Anscombe's major works include Intention, the paper Modern Moral Philosophy, and An Introduction to Wittgenstein's Tractatus. Intention is considered the founding work of the philosophy of action, while Modern Moral Philosophy transformed 20th-century ethics by calling for a return to virtue-based moral thinking." },
    { question: "What is Anscombe's critique of modern moral philosophy?", answer: "G.E.M. Anscombe argued in her 1958 paper that modern moral philosophy is incoherent because it uses concepts like moral obligation and moral law that only make sense within a divine command framework, which modern secular philosophers have rejected. She proposed that philosophers should abandon these concepts and return to Aristotelian virtue ethics, focused on character and human flourishing rather than rules and duties." },
  ],
  'w-v-o-quine': [
    { question: 'Who was W.V.O. Quine?', answer: 'W.V.O. Quine (1908-2000) was an American philosopher and logician who spent his career at Harvard, where he became a dominant figure in analytic philosophy. His attack on the analytic-synthetic distinction demolished a pillar of logical positivism, and his naturalized epistemology redefined the relationship between philosophy and science.' },
    { question: 'What did W.V.O. Quine believe?', answer: 'W.V.O. Quine believed that the boundary between philosophy and science does not exist. He argued that the distinction between analytic truths (true by definition) and synthetic truths (true by fact) cannot be maintained, and that our beliefs face the tribunal of experience not individually but only as a corporate body, meaning any belief can be revised.' },
    { question: 'Why is W.V.O. Quine important?', answer: 'W.V.O. Quine is important because his attack on the analytic-synthetic distinction in Two Dogmas of Empiricism was one of the most consequential papers in 20th-century philosophy, undermining the foundations of logical positivism. His naturalized epistemology and thesis of the indeterminacy of translation reshaped how philosophers understand knowledge, meaning, and ontology.' },
    { question: "What are W.V.O. Quine's major works?", answer: "W.V.O. Quine's major works include Word and Object, From a Logical Point of View, Methods of Logic, and Ontological Relativity and Other Essays. From a Logical Point of View contains his famous paper Two Dogmas of Empiricism, which challenged the foundations of logical positivism." },
    { question: "What is Quine's attack on the analytic-synthetic distinction?", answer: "W.V.O. Quine argued in Two Dogmas of Empiricism that the supposed distinction between analytic statements (true by meaning alone, like 'all bachelors are unmarried') and synthetic statements (true by empirical fact) cannot be clearly drawn. No statement is immune from revision in the face of experience, meaning the boundary between conceptual truth and factual truth is blurred." },
  ],
  'thomas-nagel': [
    { question: 'Who is Thomas Nagel?', answer: 'Thomas Nagel (born 1937) is an American philosopher who has held positions at Berkeley, Princeton, and New York University. His 1974 essay What Is It Like to Be a Bat? is one of the most widely assigned readings in philosophy, and his work spans philosophy of mind, ethics, epistemology, and political philosophy.' },
    { question: 'What does Thomas Nagel believe?', answer: 'Thomas Nagel believes that there is something that it is like to be a conscious organism, and that this subjective character of experience cannot be captured by objective, third-person scientific descriptions. He argues that the mind-body problem is real and that reductive materialism fails to account for consciousness, while also defending moral realism in ethics.' },
    { question: 'Why is Thomas Nagel important?', answer: 'Thomas Nagel is important because his bat essay established the subjective character of conscious experience as a central philosophical problem and influenced all subsequent work on consciousness. His book The View from Nowhere is considered an ideal introduction to the tensions between objective and subjective perspectives that lie at the heart of philosophy.' },
    { question: "What are Thomas Nagel's major works?", answer: "Thomas Nagel's major works include What Is It Like to Be a Bat?, The View from Nowhere, Mortal Questions, Mind and Cosmos, and The Possibility of Altruism. These works address consciousness, ethics, the limits of objectivity, and the philosophical foundations of moral motivation." },
    { question: "What is Nagel's 'What Is It Like to Be a Bat?'", answer: "Thomas Nagel's famous essay argues that even if we knew everything about bat neurology and sonar, we would still not know what it is like to be a bat, the subjective character of bat experience. This demonstrates that conscious experience has an irreducibly subjective aspect that cannot be captured by any objective scientific account, no matter how complete." },
  ],
  'daniel-dennett': [
    { question: 'Who was Daniel Dennett?', answer: 'Daniel Dennett (1942-2024) was an American philosopher and cognitive scientist who spent his career at Tufts University. Trained at Harvard under Quine and at Oxford under Ryle, he was a prominent defender of the view that consciousness can be fully explained in terms of brain processes and was known as one of the Four Horsemen of New Atheism.' },
    { question: 'What did Daniel Dennett believe?', answer: 'Daniel Dennett believed that consciousness is not what it seems and that what it seems is all it is. He argued that consciousness can be fully explained by neuroscience and cognitive science without invoking any mysterious non-physical properties, and that free will is compatible with determinism when properly understood.' },
    { question: 'Why is Daniel Dennett important?', answer: 'Daniel Dennett is important because he provided the most sustained philosophical defense of the view that consciousness can be explained through natural science. His work influenced cognitive science, artificial intelligence research, and public discourse on religion, and his concept of the intentional stance became a widely used tool in philosophy of mind.' },
    { question: "What are Daniel Dennett's major works?", answer: "Daniel Dennett's major works include Consciousness Explained, Darwin's Dangerous Idea, Freedom Evolves, Intuition Pumps and Other Tools for Thinking, and I've Been Thinking. Consciousness Explained presents his deflationary theory of consciousness, while Darwin's Dangerous Idea extends evolutionary thinking to culture and meaning." },
    { question: "What is Dennett's view on consciousness?", answer: "Daniel Dennett argued that consciousness does not have the special, mysterious properties most people assume it does. He rejected the idea of qualia as irreducible subjective experiences and proposed that consciousness is a set of cognitive processes that can be fully explained by brain science. His multiple drafts model replaced the idea of a unified conscious experience with a distributed process of parallel narrative construction." },
  ],
  'david-chalmers': [
    { question: 'Who is David Chalmers?', answer: 'David Chalmers (born 1966) is an Australian philosopher and cognitive scientist at New York University. Trained in mathematics before switching to philosophy, he established himself as the leading voice arguing that consciousness cannot be reduced to physical processes, and he co-directs NYU\'s Center for Mind, Brain, and Consciousness.' },
    { question: 'What does David Chalmers believe?', answer: 'David Chalmers believes that consciousness poses a hard problem: explaining why physical processes give rise to subjective experience at all. He argues that even a complete account of the brain\'s functional operations would leave unanswered why there is something it is like to have those operations, and that new fundamental principles may be needed to explain consciousness.' },
    { question: 'Why is David Chalmers important?', answer: 'David Chalmers is important because he formulated the hard problem of consciousness, which has become the central organizing question in the philosophy of mind. His 1996 book The Conscious Mind established the case against reductive physicalism with a rigor that made it impossible for philosophers of mind to ignore the explanatory gap between brain processes and subjective experience.' },
    { question: "What are David Chalmers's major works?", answer: "David Chalmers's major works include The Conscious Mind, The Character of Consciousness, Reality+: Virtual Worlds and the Problems of Philosophy, and Constructing the World. The Conscious Mind is his foundational argument against reductive physicalism, while Reality+ explores philosophical questions raised by virtual and digital worlds." },
    { question: "What is Chalmers's hard problem of consciousness?", answer: "David Chalmers's hard problem of consciousness asks why physical processes in the brain give rise to subjective experience at all. Even if we can explain how the brain processes information and controls behavior (the easy problems), we still face the question of why there is something it is like to see red or feel pain. This explanatory gap between physical processes and subjective experience is what makes the problem hard." },
  ],
  'judith-jarvis-thomson': [
    { question: 'Who was Judith Jarvis Thomson?', answer: 'Judith Jarvis Thomson (1929-2020) was an American moral philosopher who spent her career at MIT. Her 1971 essay A Defense of Abortion is one of the most widely anthologized papers in philosophy, and she named and developed the trolley problem into the form now known worldwide, generating a vast literature spanning philosophy, psychology, and neuroscience.' },
    { question: 'What did Judith Jarvis Thomson believe?', answer: 'Judith Jarvis Thomson believed that even if a fetus has a right to life, it does not follow that a woman is morally required to sustain it with her body. She used innovative thought experiments to argue that rights are not absolute and that the relationship between rights, duties, and moral permissibility is more complex than commonly assumed.' },
    { question: 'Why is Judith Jarvis Thomson important?', answer: 'Judith Jarvis Thomson is important because her violinist thought experiment transformed the abortion debate by shifting focus from the moral status of the fetus to the question of what one person can be required to sacrifice for another. She also developed the trolley problem into its most influential form, generating an entire subfield of moral philosophy.' },
    { question: "What are Judith Jarvis Thomson's major works?", answer: "Judith Jarvis Thomson's major works include the essays A Defense of Abortion and The Trolley Problem, along with the books The Realm of Rights, Rights, Restitution, and Risk, and Normativity. A Defense of Abortion appeared in the inaugural issue of Philosophy & Public Affairs and became one of the most discussed papers in applied ethics." },
    { question: "What is Thomson's violinist argument?", answer: "Judith Jarvis Thomson's violinist argument asks you to imagine waking up connected to an unconscious violinist who needs your kidneys to survive. Even granting that the violinist has a right to life, Thomson argued, you are not morally required to remain connected for nine months. Similarly, she argued, even if a fetus has a right to life, it does not automatically follow that a woman must sustain it with her body against her will." },
  ],
};
